/**
 * Reporter logging and summary rendering utilities
 */

import type { FullResult } from '@playwright/test/reporter';
import type { CoverageDataEvent, RunMetadata } from '../types/index.js';

// Dynamic import for chalk (ESM-only package)
let chalkPromise: Promise<typeof import('chalk').default> | null = null;

/**
 * Dynamically import chalk (ESM-only package) for CJS compatibility only once per process using memoization.
 *
 * @returns Promise resolving to the chalk default export
 * @throws Never - returns plain text fallback on import failure
 */
async function getChalk(): Promise<typeof import('chalk').default> {
  if (!chalkPromise) {
    chalkPromise = import('chalk')
      .then((m) => m.default)
      .catch((error) => {
        console.warn('⚠️  TestDino: Failed to load chalk, using plain text output');
        console.debug('Chalk import error:', error.message);
        // Return no-op chalk that returns strings unchanged
        return {
          green: (s: string) => s,
          yellow: (s: string) => s,
          red: (s: string) => s,
          blue: (s: string) => s,
          cyan: (s: string) => s,
          dim: (s: string) => s,
          bold: (s: string) => s,
        } as unknown as typeof import('chalk').default;
      });
  }
  return chalkPromise;
}

export interface ReporterLogOptions {
  debug: boolean;
}

export interface RunSummaryData {
  runId: string;
  runMetadata: RunMetadata | null;
  testCounts: {
    passed: number;
    failed: number;
    skipped: number;
    timedOut: number;
    interrupted: number;
    flaky: number;
    retried: number;
  };
  totalTests: number;
  workerCount: number;
  projectNames: Set<string>;
  shardInfo?: { current: number; total: number };
  lastCoverageEvent: CoverageDataEvent | null;
}

// ── Formatting helpers (exported for testing) ──

function stripAnsi(str: string): string {
  // eslint-disable-next-line no-control-regex
  return str.replace(/\u001b\[[0-9;]*m/g, '');
}

export function pad(str: string, len: number): string {
  const vLen = stripAnsi(str).length;
  return vLen >= len ? str : str + ' '.repeat(len - vLen);
}

export function padStart(str: string, len: number): string {
  const vLen = stripAnsi(str).length;
  return vLen >= len ? str : ' '.repeat(len - vLen) + str;
}

export function formatDuration(ms: number): string {
  if (ms < 1000) return `${ms}ms`;
  const seconds = ms / 1000;
  if (seconds < 60) return `${seconds.toFixed(1)}s`;
  const minutes = Math.floor(seconds / 60);
  const remainingSeconds = (seconds % 60).toFixed(0);
  return `${minutes}m ${remainingSeconds}s`;
}

export function shortenPath(filePath: string): string {
  const markers = ['/src/', '/lib/', '/app/'];
  for (const marker of markers) {
    const idx = filePath.indexOf(marker);
    if (idx !== -1) return filePath.slice(idx + 1);
  }
  const parts = filePath.split('/');
  return parts.length > 2 ? parts.slice(-2).join('/') : filePath;
}

type ChalkInstance = typeof import('chalk').default;

export function colorPct(pct: number, chalk: ChalkInstance): string {
  const color = pct >= 80 ? chalk.green : pct >= 50 ? chalk.yellow : chalk.red;
  return color(pct === 100 ? '100%' : `${pct.toFixed(1)}%`);
}

// ── Summary rendering ──

function printCoverageTableWithChalk(event: CoverageDataEvent, chalk: ChalkInstance): void {
  const { summary, files } = event;
  const row = (content: string) => `  ${chalk.dim('│')} ${content}`;
  const nameW = 30;
  const colW = 10;

  console.log(row(`${chalk.bold('Coverage')}  ${chalk.dim(`${files.length} files`)}`));
  console.log(row(''));

  // Header
  console.log(
    row(
      `  ${chalk.dim(`${pad('File', nameW)}${padStart('Stmts', colW)}${padStart('Branch', colW)}${padStart('Funcs', colW)}${padStart('Lines', colW)}`)}`
    )
  );

  // Per-file rows
  for (const file of files) {
    const name = shortenPath(file.path);
    const short = name.length > nameW ? name.slice(0, nameW - 1) + '~' : name;
    console.log(
      row(
        `  ${pad(short, nameW)}` +
          padStart(colorPct(file.statements.pct, chalk), colW) +
          padStart(colorPct(file.branches.pct, chalk), colW) +
          padStart(colorPct(file.functions.pct, chalk), colW) +
          padStart(colorPct(file.lines.pct, chalk), colW)
      )
    );
  }

  // Separator + totals
  console.log(row(`  ${chalk.dim('─'.repeat(nameW + colW * 4))}`));
  console.log(
    row(
      `  ${chalk.bold(pad('All files', nameW))}` +
        padStart(colorPct(summary.statements.pct, chalk), colW) +
        padStart(colorPct(summary.branches.pct, chalk), colW) +
        padStart(colorPct(summary.functions.pct, chalk), colW) +
        padStart(colorPct(summary.lines.pct, chalk), colW)
    )
  );
}

function printRunSummaryWithChalk(result: FullResult, data: RunSummaryData, chalk: ChalkInstance): void {
  const W = 72;
  const topBorder = `  ${chalk.dim(`┌${'─'.repeat(W)}┐`)}`;
  const bottomBorder = `  ${chalk.dim(`└${'─'.repeat(W)}┘`)}`;
  const divider = `  ${chalk.dim(`├${'─'.repeat(W)}┤`)}`;
  const row = (content: string) => `  ${chalk.dim('│')} ${content}`;

  console.log('');
  console.log(topBorder);
  console.log(row(chalk.bold('TestDino Run Summary')));
  console.log(divider);

  // Run & Git
  console.log(row(`${chalk.dim('Run')}   ${data.runId}`));
  const git = data.runMetadata?.git;
  if (git?.branch || git?.commit?.hash) {
    const branch = git.branch ? chalk.cyan(git.branch) : '';
    const sha = git.commit?.hash ? chalk.dim(git.commit.hash.slice(0, 7)) : '';
    const sep = branch && sha ? `  ${chalk.dim('@')}  ` : '';
    const msg = git.commit?.message ? `  ${chalk.dim(git.commit.message.split('\n')[0].slice(0, 50))}` : '';
    console.log(row(`${chalk.dim('Git')}   ${branch}${sep}${sha}${msg}`));
  }

  console.log(divider);

  // Test Results
  const statusColor = result.status === 'passed' ? chalk.green : result.status === 'failed' ? chalk.red : chalk.yellow;
  const statusLabel = result.status === 'timedout' ? 'timed out' : result.status;
  console.log(
    row(
      `${chalk.bold('Tests')}  ${statusColor(statusLabel.toUpperCase())}  ${chalk.dim(formatDuration(result.duration))}`
    )
  );

  const counts: string[] = [];
  if (data.testCounts.passed > 0) counts.push(chalk.green(`${data.testCounts.passed} passed`));
  if (data.testCounts.failed > 0) counts.push(chalk.red(`${data.testCounts.failed} failed`));
  if (data.testCounts.flaky > 0) counts.push(chalk.yellow(`${data.testCounts.flaky} flaky`));
  if (data.testCounts.skipped > 0) counts.push(chalk.dim(`${data.testCounts.skipped} skipped`));
  if (data.testCounts.timedOut > 0) counts.push(chalk.red(`${data.testCounts.timedOut} timed out`));
  if (data.testCounts.interrupted > 0) counts.push(chalk.yellow(`${data.testCounts.interrupted} interrupted`));
  const retriedStr = data.testCounts.retried > 0 ? `  ${chalk.dim(`(${data.testCounts.retried} retries)`)}` : '';
  console.log(row(`       ${counts.join(chalk.dim(' · '))}  ${chalk.dim(`of ${data.totalTests}`)}${retriedStr}`));

  // Workers & Shards
  console.log(divider);
  const shardStr = data.shardInfo ? `${data.shardInfo.current}/${data.shardInfo.total}` : '—';
  console.log(
    row(
      `${pad(`${chalk.dim('Workers')}  ${data.workerCount > 0 ? data.workerCount : '—'}`, 28)}` +
        `${pad(`${chalk.dim('Shard')}  ${shardStr}`, 28)}` +
        `${chalk.dim('Projects')}  ${data.projectNames.size > 0 ? Array.from(data.projectNames).join(', ') : '—'}`
    )
  );

  // Coverage
  if (data.lastCoverageEvent) {
    console.log(divider);
    printCoverageTableWithChalk(data.lastCoverageEvent, chalk);
  }

  console.log(bottomBorder);
  console.log('');
}

/**
 * Create a reporter log helper with consistent prefixes.
 * printRunSummary and printCoverageTable use dynamic chalk import (async).
 */
export const createReporterLog = (options: ReporterLogOptions) => ({
  success: (msg: string) => console.log(`✅ TestDino: ${msg}`),
  warn: (msg: string) => console.warn(`⚠️  TestDino: ${msg}`),
  error: (msg: string) => console.error(`❌ TestDino: ${msg}`),
  info: (msg: string) => console.log(`ℹ️ TestDino: ${msg}`),
  debug: (msg: string) => {
    if (options.debug) {
      console.log(`🔍 TestDino: ${msg}`);
    }
  },
  printRunSummary: async (result: FullResult, data: RunSummaryData): Promise<void> => {
    const chalk = await getChalk();
    printRunSummaryWithChalk(result, data, chalk);
  },
  printCoverageTable: async (event: CoverageDataEvent): Promise<void> => {
    const chalk = await getChalk();
    printCoverageTableWithChalk(event, chalk);
  },
});

export type ReporterLog = ReturnType<typeof createReporterLog>;
