/**
 * SAS Token client for requesting Azure Blob Storage upload tokens
 */

import axios, { type AxiosInstance } from 'axios';
import type { SASTokenResponse, SASTokenServerResponse } from './types.js';
import { sleep } from '../utils/index.js';

export interface SASTokenClientOptions {
  token: string;
  serverUrl: string;
  maxAttempts?: number;
  retryDelay?: number;
}

/**
 * Client for requesting SAS tokens from TestDino server
 */
export class SASTokenClient {
  private client: AxiosInstance;
  private options: Required<SASTokenClientOptions>;

  constructor(options: SASTokenClientOptions) {
    this.options = {
      maxAttempts: 2,
      retryDelay: 1000,
      ...options,
    };

    // Use x-api-key header for storage endpoint (different from Bearer token)
    this.client = axios.create({
      baseURL: this.options.serverUrl,
      headers: {
        'Content-Type': 'application/json',
        'x-api-key': this.options.token,
      },
      timeout: 10000,
    });
  }

  /**
   * Request SAS token for artifact uploads
   * @param expiryHours - Token validity duration (1-48 hours, default 48)
   * @returns SAS token response with upload instructions
   */
  async requestToken(expiryHours: number = 48): Promise<SASTokenResponse> {
    let lastError: Error | null = null;

    for (let attempt = 0; attempt < this.options.maxAttempts; attempt++) {
      try {
        const response = await this.client.post<SASTokenServerResponse>('/api/storage/token', undefined, {
          params: {
            expiryHours,
            permissions: 'write,create',
          },
        });

        if (!response.data.success) {
          throw new Error(response.data.message || 'SAS token request failed');
        }

        return response.data.data;
      } catch (error) {
        lastError = new Error(this.getErrorMessage(error));

        if (attempt < this.options.maxAttempts - 1) {
          // Wait before retry with exponential backoff
          const delay = this.options.retryDelay * Math.pow(2, attempt);
          await sleep(delay);
        }
      }
    }

    throw lastError || new Error('Failed to request SAS token');
  }

  /**
   * Extract error message from various error types
   */
  private getErrorMessage(error: unknown): string {
    if (axios.isAxiosError(error)) {
      // Handle specific HTTP status codes
      if (error.response?.status === 401) {
        return 'Invalid API key for artifact uploads';
      }
      if (error.response?.status === 403) {
        return 'API key does not have write permission for uploads';
      }
      if (error.response?.status === 429) {
        return 'Rate limit exceeded for SAS token requests';
      }
      return error.response?.data?.message || error.message;
    }
    if (error instanceof Error) {
      return error.message;
    }
    return String(error);
  }
}
