/**
 * TestDino Playwright Reporter
 * Streams test execution data in real-time
 */

import type {
  Reporter,
  FullConfig,
  Suite,
  TestCase,
  TestResult,
  TestStep,
  FullResult,
  TestError,
} from '@playwright/test/reporter';
import { randomUUID } from 'crypto';
import { readFileSync, existsSync } from 'fs';
import { HttpClient } from '../streaming/http.js';
import { KafkaEventProducer } from '../streaming/kafka.js';

import { EventBuffer } from '../streaming/buffer.js';
import { EventDeliveryManager } from '../streaming/delivery.js';
import { createMetadataCollector } from '../metadata/index.js';
import type {
  TestdinoConfig,
  TestEvent,
  TestRunBeginEvent,
  TestBeginEvent,
  TestStepBeginEvent,
  TestStepEndEvent,
  TestEndEvent,
  TestRunEndEvent,
  TestRunErrorEvent,
  TestConsoleOutEvent,
  TestConsoleErrEvent,
  CoverageDataEvent,
  RunMetadata,
  Annotation,
} from '../types/index.js';
import { ArtifactUploader, SASTokenClient, type UploadResult, type AttachmentForUpload } from '../uploads/index.js';
import { CoverageMerger, extractCompactCounts, generateIstanbulHtmlReport } from '../code-coverage/index.js';
import type { CoverageFragment } from '../code-coverage/index.js';
import { createReporterLog, type ReporterLog, type RunSummaryData } from './log.js';
import { QuotaExhaustedError } from './errors.js';
import { isDebugEnabled } from '../utils/index.js';

// Maximum console chunk size (10KB in characters)
const MAX_CONSOLE_CHUNK_SIZE = 10_000;

// Maximum number of events to buffer
const MAX_BUFFER_SIZE = 10;

// File count threshold for coverage size warning
const COVERAGE_FILE_COUNT_WARNING = 500;

export class TestdinoReporter implements Reporter {
  private config: TestdinoConfig;
  private buffer: EventBuffer | null = null;
  private runId: string;
  private sequenceNumber = 0;

  // Shard and timing info for interruption handling
  private shardInfo?: { current: number; total: number };
  private runStartTime?: number;

  // Signal handler management
  private sigintHandler?: () => void;
  private sigtermHandler?: () => void;
  private isShuttingDown = false;

  // Quota tracking
  private quotaExceeded = false;

  // HTTP client for authentication
  private httpClient: HttpClient | null = null;
  private projectId: string | null = null;

  // Kafka event producer
  private kafkaProducer: KafkaEventProducer | null = null;

  // Delivery manager (retry + HTTP fallback)
  private deliveryManager: EventDeliveryManager | null = null;

  // Artifact upload
  private artifactUploader: ArtifactUploader | null = null;
  private artifactsEnabled = true; // Default: enabled

  // Deferred initialization - resolves true on success, false on failure
  private initPromise: Promise<boolean> | null = null;
  private initFailed = false;

  // Promises for onTestEnd; must be awaited in onEnd to prevent data loss
  private pendingTestEndPromises: Set<Promise<void>> = new Set();

  // Logger for consistent output
  private log: ReporterLog;

  // Coverage collection
  private coverageEnabled = false;
  private coverageMerger: CoverageMerger | null = null;
  private warnedCoverageDisconnect = false;
  private coverageThresholdFailed = false;

  // Test result tracking for summary
  private testCounts = { passed: 0, failed: 0, skipped: 0, timedOut: 0, interrupted: 0, flaky: 0, retried: 0 };
  private totalTests = 0;
  private lastCoverageEvent: CoverageDataEvent | null = null;

  // Detailed tracking for summary output
  private projectNames = new Set<string>();
  private runMetadata: RunMetadata | null = null;
  private workerCount = 0;

  constructor(config: TestdinoConfig = {}) {
    // Load CLI config if available
    const cliConfig = this.loadCliConfig();

    // Merge configs: CLI config takes precedence over constructor config
    this.config = { ...config, ...cliConfig };

    this.runId = randomUUID();

    // Initialize logger with debug setting from config
    this.log = createReporterLog({ debug: this.config.debug ?? false });

    // Initialize coverage merger if coverage is enabled
    this.coverageEnabled = this.config.coverage?.enabled ?? false;
    if (this.coverageEnabled) {
      this.coverageMerger = new CoverageMerger({
        include: this.config.coverage?.include,
        exclude: this.config.coverage?.exclude,
        onError: (msg) => this.log.warn(msg),
      });
    }

    // Initialize artifact uploads from config (default: enabled)
    this.artifactsEnabled = this.config.artifacts !== false;

    // Create buffer early to collect events before async init; flush waits for initPromise.
    this.buffer = new EventBuffer({
      maxSize: MAX_BUFFER_SIZE,
      onFlush: async (events) => {
        if (this.initPromise) {
          const success = await this.initPromise;
          if (!success) return; // Init failed - discard events
        }
        await this.sendEvents(events);
      },
    });
  }

  /**
   * Load configuration from CLI temp file if available
   */
  private loadCliConfig(): TestdinoConfig {
    const cliConfigPath = process.env.TESTDINO_CLI_CONFIG_PATH;

    if (!cliConfigPath) {
      return {};
    }

    try {
      if (!existsSync(cliConfigPath)) {
        return {};
      }

      const configContent = readFileSync(cliConfigPath, 'utf-8');
      const cliConfig = JSON.parse(configContent) as Record<string, unknown>;

      const mappedConfig: TestdinoConfig = {};

      if (cliConfig.token !== undefined && typeof cliConfig.token === 'string') {
        mappedConfig.token = cliConfig.token;
      }

      if (cliConfig.serverUrl !== undefined && typeof cliConfig.serverUrl === 'string') {
        mappedConfig.serverUrl = cliConfig.serverUrl;
      }

      if (cliConfig.debug !== undefined && typeof cliConfig.debug === 'boolean') {
        mappedConfig.debug = cliConfig.debug;
      }

      // CI run ID for grouping sharded runs
      if (cliConfig.ciRunId !== undefined && typeof cliConfig.ciRunId === 'string') {
        mappedConfig.ciRunId = cliConfig.ciRunId;
      }

      // Handle artifacts flag
      if (cliConfig.artifacts !== undefined && typeof cliConfig.artifacts === 'boolean') {
        mappedConfig.artifacts = cliConfig.artifacts;
      }

      // Handle coverage config
      if (typeof cliConfig.coverage === 'object' && cliConfig.coverage !== null) {
        mappedConfig.coverage = cliConfig.coverage as import('../code-coverage/types.js').CoverageConfig;
      }

      return mappedConfig;
    } catch (error) {
      // Silently fail - CLI config is optional
      if (isDebugEnabled()) {
        console.warn(
          '⚠️  TestDino: Failed to load CLI config:',
          error instanceof Error ? error.message : String(error)
        );
      }
      return {};
    }
  }

  /**
   * Called once before running tests
   */
  async onBegin(config: FullConfig, suite: Suite): Promise<void> {
    // Check if we're a duplicate instance (CLI-injected when already in config)
    if (config && this.isDuplicateInstance(config.reporter)) {
      if (this.config.debug) {
        this.log.debug('Reporter already configured in playwright.config, skipping duplicate instance');
      }
      return;
    }

    const token = this.getToken();

    if (!token) {
      this.printConfigurationError('Token is required but not provided', [
        'Set environment variable: export TESTDINO_TOKEN=your-token',
        'Add to playwright.config.ts: token: "your-token"',
        'Use CLI wrapper: npx tdpw test --token your-token',
      ]);
      return;
    }

    // Store shard info and run start time for potential interruption handling
    if (config?.shard) {
      this.shardInfo = {
        current: config.shard.current,
        total: config.shard.total,
      };
    }
    this.runStartTime = Date.now();

    // Kick off async initialization without awaiting - Playwright does not await onBegin. Events will be buffered and transmitted once init completes.
    this.initPromise = this.performAsyncInit(config, suite, token);
  }

  /**
   * Perform all async initialization: auth, metadata, Kafka connect, run:begin
   *
   * Buffer's onFlush callback awaits this promise before transmitting events,
   * ensuring no data is sent before authentication and connection are established.
   *
   * @param config - Playwright FullConfig for metadata collection
   * @param suite - Playwright Suite for skeleton building
   * @param token - Authentication token
   * @returns true on success, false on failure
   */
  private async performAsyncInit(config: FullConfig, suite: Suite, token: string): Promise<boolean> {
    const serverUrl = this.getServerUrl();

    try {
      // Register signal handlers early so SIGINT during init still cleans up
      this.registerSignalHandlers();

      // Authenticate with the TestDino server
      this.httpClient = new HttpClient({ token, serverUrl });
      const auth = await this.httpClient.authenticate();
      this.projectId = auth.projectId;
      this.log.success('Authenticated successfully');

      // Initialize artifact uploads if enabled
      if (this.artifactsEnabled) {
        try {
          const sasClient = new SASTokenClient({ token, serverUrl });
          const sasToken = await sasClient.requestToken();
          this.artifactUploader = new ArtifactUploader(sasToken, { debug: this.config.debug });
          this.log.info('Artifact uploads initialized');
        } catch (error) {
          this.log.warn(`Artifact uploads disabled: ${error instanceof Error ? error.message : String(error)}`);
          this.artifactsEnabled = false;
        }
      }

      // Collect metadata
      const metadata = await this.collectMetadata(config, suite);
      this.runMetadata = metadata;
      this.workerCount = config.workers;

      // Build run:begin event — sent directly (not via buffer) to guarantee
      // it is the first event. initPromise resolves only after delivery,
      // so buffer's onFlush will transmit buffered events after run:begin.
      const beginEvent: TestRunBeginEvent = {
        type: 'run:begin',
        runId: this.runId,
        projectId: this.projectId!,
        metadata,
        ciRunId: this.config.ciRunId,
        timestamp: Date.now(),
        sequence: 0,
      };

      // Debug logging for run:begin event details
      if (this.config.debug) {
        const shardInfo = config?.shard ? `${config.shard.current}/${config.shard.total}` : 'none';
        const skeletonInfo = metadata.skeleton
          ? `${metadata.skeleton.totalTests} tests, ${metadata.skeleton.suites?.length ?? 0} suites`
          : 'not available';
        this.log.debug(
          `run:begin runId=${this.runId} ciRunId=${this.config.ciRunId ?? 'none'} shard=${shardInfo} skeleton=(${skeletonInfo})`
        );
      }

      // Connect to Kafka using config from auth response
      if (auth.kafka) {
        this.kafkaProducer = new KafkaEventProducer({
          brokers: auth.kafka.brokers,
          topic: auth.kafka.topic ?? 'testdino-events',
          clientId: `testdino-reporter-${this.runId.slice(0, 8)}`,
          debug: this.config.debug,
          ...(auth.kafka.sasl && { sasl: auth.kafka.sasl }),
          ...(auth.kafka.ssl !== undefined && { ssl: auth.kafka.ssl }),
        });
        await this.kafkaProducer.connect();

        // Create delivery manager with retry + HTTP fallback
        this.deliveryManager = new EventDeliveryManager({
          kafkaProducer: this.kafkaProducer,
          httpClient: this.httpClient!,
          debug: this.config.debug,
          onDebug: (msg) => this.log.debug(msg),
          onError: (msg) => this.log.error(msg),
          onWarn: (msg) => this.log.warn(msg),
        });

        // Send run:begin and wait for broker ack before allowing any other events
        await this.kafkaProducer.send(beginEvent);
        this.log.info('run:begin delivered and acknowledged by Kafka');
      }

      return true;
    } catch (error) {
      if (error instanceof QuotaExhaustedError) {
        this.quotaExceeded = true;
        this.log.warn(`Quota exhausted: ${error.message}`);
        if (error.details.resetDate) {
          this.log.warn(`Quota resets on ${error.details.resetDate}. Plan: ${error.details.planName}`);
        }
        return false;
      }
      this.initFailed = true;
      this.log.error(`Failed to initialize reporter: ${error instanceof Error ? error.message : String(error)}`);
      return false;
    }
  }

  /**
   * Called for each test before it starts
   */
  async onTestBegin(test: TestCase, result: TestResult): Promise<void> {
    if (!this.initPromise || this.initFailed) return;

    const event: TestBeginEvent = {
      type: 'test:begin',
      runId: this.runId,
      ...this.getEventMetadata(),

      // Test identification
      testId: test.id,
      title: test.title,
      titlePath: test.titlePath(),

      // Location information
      location: {
        file: test.location.file,
        line: test.location.line,
        column: test.location.column,
      },

      // Test configuration
      tags: test.tags,
      expectedStatus: test.expectedStatus,
      timeout: test.timeout,
      retries: test.retries,
      annotations: this.extractAnnotations(test.annotations),

      // Execution context
      retry: result.retry,
      workerIndex: result.workerIndex,
      parallelIndex: result.parallelIndex,
      repeatEachIndex: test.repeatEachIndex,

      // Hierarchy information
      parentSuite: this.extractParentSuite(test.parent),

      // Timing
      startTime: result.startTime.getTime(),
    };

    await this.buffer!.add(event);
  }

  /**
   * Called when a test step begins
   */
  async onStepBegin(test: TestCase, result: TestResult, step: TestStep): Promise<void> {
    if (!this.initPromise || this.initFailed) return;

    const event: TestStepBeginEvent = {
      type: 'step:begin',
      runId: this.runId,
      ...this.getEventMetadata(),

      // Step Identification
      testId: test.id,
      stepId: `${test.id}-${step.titlePath().join('-')}`,
      title: step.title,
      titlePath: step.titlePath(),

      // Step Classification
      category: step.category,

      // Location Information
      location: step.location
        ? {
            file: step.location.file,
            line: step.location.line,
            column: step.location.column,
          }
        : undefined,

      // Hierarchy Information
      parentStep: step.parent ? this.extractParentStep(step.parent) : undefined,

      // Timing
      startTime: step.startTime.getTime(),

      // Retry Information
      retry: result.retry,

      // Worker Information
      workerIndex: result.workerIndex,
      parallelIndex: result.parallelIndex,

      // Annotations
      annotations: this.extractAnnotations(step.annotations),
    };

    await this.buffer!.add(event);
  }

  /**
   * Called when a test step ends
   */
  async onStepEnd(test: TestCase, result: TestResult, step: TestStep): Promise<void> {
    if (!this.initPromise || this.initFailed) return;

    // Derive status from error presence
    const status: 'passed' | 'failed' = step.error ? 'failed' : 'passed';

    const event: TestStepEndEvent = {
      type: 'step:end',
      runId: this.runId,
      ...this.getEventMetadata(),

      // Step Identification
      testId: test.id,
      stepId: `${test.id}-${step.titlePath().join('-')}`,
      title: step.title,
      titlePath: step.titlePath(),

      // Timing
      duration: step.duration,

      // Error Information
      error: this.extractError(step.error),

      // Status Information
      status,

      // Child Steps Summary
      childSteps: this.extractChildSteps(step),

      // Attachments Metadata
      attachments: this.extractAttachments(step),

      // Annotations
      annotations: this.extractAnnotations(step.annotations),

      // Retry Information
      retry: result.retry,

      // Worker Information
      workerIndex: result.workerIndex,
      parallelIndex: result.parallelIndex,
    };

    await this.buffer!.add(event);
  }

  /**
   * Called after each test.
   * Playwright does not await onTestEnd promises—pending work is awaited in onEnd.
   */
  onTestEnd(test: TestCase, result: TestResult): void {
    if (!this.initPromise || this.initFailed) return;

    // Warn when fixture sends coverage data but coverage is disabled in config
    if (!this.coverageEnabled && !this.warnedCoverageDisconnect) {
      const hasCoverageAttachment = result.attachments.some((a) => a.name === 'testdino-coverage');
      if (hasCoverageAttachment) {
        this.log.warn(
          'Coverage data detected but coverage.enabled is false — ' +
            'set coverage: { enabled: true } to collect coverage'
        );
        this.warnedCoverageDisconnect = true;
      }
    }

    // Extract and merge coverage fragment (if coverage enabled)
    if (this.coverageEnabled && this.coverageMerger) {
      this.extractCoverageFromResult(result, this.coverageMerger);
    }

    // Track project name
    const projectName = this.getProjectName(test);
    if (projectName) {
      this.projectNames.add(projectName);
    }

    // Track test result counts for summary table display
    if (result.retry > 0) {
      this.testCounts.retried++;
    }
    // Only count final status on the last attempt (for summary table display)
    const isFinalAttempt = result.status === 'passed' || result.retry === test.retries;
    if (isFinalAttempt) {
      this.totalTests++;
      const outcome = test.outcome();
      if (outcome === 'flaky') {
        this.testCounts.flaky++;
      } else if (result.status === 'passed') {
        this.testCounts.passed++;
      } else if (result.status === 'failed') {
        this.testCounts.failed++;
      } else if (result.status === 'skipped') {
        this.testCounts.skipped++;
      } else if (result.status === 'timedOut') {
        this.testCounts.timedOut++;
      } else if (result.status === 'interrupted') {
        this.testCounts.interrupted++;
      }
    }

    // Create and track the async work - Playwright does not await onTestEnd
    const workPromise = this.processTestEnd(test, result);
    this.pendingTestEndPromises.add(workPromise);

    // Remove from tracking when complete (success or failure)
    workPromise.finally(() => {
      this.pendingTestEndPromises.delete(workPromise);
    });
  }

  /**
   * Process test end event asynchronously
   * Uploads attachments and adds test:end event to buffer
   */
  private async processTestEnd(test: TestCase, result: TestResult): Promise<void> {
    try {
      // Upload attachments and get Azure URLs (if upload enabled)
      const attachmentsWithUrls = await this.uploadAttachments(result.attachments, test.id);

      const event: TestEndEvent = {
        type: 'test:end',
        runId: this.runId,
        ...this.getEventMetadata(),

        // Test Identification
        testId: test.id,

        // Status Information
        status: result.status as 'passed' | 'failed' | 'skipped' | 'timedOut' | 'interrupted',
        outcome: test.outcome(),

        // Timing
        duration: result.duration,

        // Execution Context
        retry: result.retry,

        // Worker Information
        workerIndex: result.workerIndex,
        parallelIndex: result.parallelIndex,

        // Test Metadata
        annotations: this.extractAnnotations(result.annotations),

        // Error Information
        errors: result.errors
          .map((e) => this.extractError(e))
          .filter((e): e is NonNullable<typeof e> => e !== undefined),

        // Step Summary
        steps: this.extractTestStepsSummary(result),

        // Attachments Metadata (with Azure URLs when uploaded)
        attachments: attachmentsWithUrls,

        // Console Output
        stdout: result.stdout.length > 0 ? this.extractConsoleOutput(result.stdout) : undefined,
        stderr: result.stderr.length > 0 ? this.extractConsoleOutput(result.stderr) : undefined,
      };

      await this.buffer!.add(event);
    } catch (error) {
      // Log error but don't throw - one test failure shouldn't break others
      this.log.error(`Failed to process test:end event: ${error instanceof Error ? error.message : String(error)}`);
    }
  }

  /**
   * Called after all tests complete
   */
  async onEnd(result: FullResult): Promise<{ status?: FullResult['status'] } | void> {
    // If quota exceeded, skip event transmission but still cleanup
    if (this.quotaExceeded) {
      // Await pending test:end promises for graceful cleanup (even though we won't send events)
      if (this.pendingTestEndPromises.size > 0) {
        await Promise.allSettled(Array.from(this.pendingTestEndPromises));
      }
      this.log.success('Tests completed (quota limit reached; not streamed to TestDino)');
      await this.kafkaProducer?.close();
      this.removeSignalHandlers();
      return;
    }

    // If init was never started (no token, duplicate), nothing to do
    if (!this.initPromise) return;

    // Ensure initialization completes before flushing events
    const success = await this.initPromise;
    if (!success) {
      // Init failed - await pending test:end promises before cleanup so they
      // don't fire after resources are torn down (floating promise prevention)
      if (this.pendingTestEndPromises.size > 0) {
        await Promise.allSettled(Array.from(this.pendingTestEndPromises));
      }
      this.buffer?.clear();
      this.pendingTestEndPromises.clear();
      await this.kafkaProducer?.close();
      this.removeSignalHandlers();
      return;
    }

    // Await completion of all pending test:end events before flushing final events
    if (this.pendingTestEndPromises.size > 0) {
      this.log.debug(`Waiting for ${this.pendingTestEndPromises.size} pending test:end events...`);
      // Use Promise.allSettled for error isolation - one failed test shouldn't block others
      await Promise.allSettled(Array.from(this.pendingTestEndPromises));
    }

    // Send coverage data before run:end (if coverage collected)
    if (this.coverageEnabled && this.coverageMerger?.hasCoverage) {
      try {
        // Build coverage event (includes summary, files, and compact counts for sharded runs)
        const coverageEvent = this.buildCoverageEvent(this.coverageMerger);
        await this.buffer!.add(coverageEvent);

        // Store for local console summary table
        this.lastCoverageEvent = coverageEvent;

        // Check coverage thresholds
        const thresholdFailures = this.checkCoverageThresholds(coverageEvent.summary);
        if (thresholdFailures.length > 0) {
          this.coverageThresholdFailed = true;
        }
      } catch (error) {
        // Log but don't fail the run
        this.log.warn(`Failed to build coverage event: ${error instanceof Error ? error.message : String(error)}`);
      }

      // Generate local HTML report if configured (separate try-catch to avoid
      // misleading "Failed to build coverage event" when only report generation fails)
      if (this.coverageMerger?.hasCoverage) {
        try {
          const outputDir = './coverage';
          const reportPath = await generateIstanbulHtmlReport(this.coverageMerger, {
            outputDir,
          });
          this.log.info(`Coverage Report: ${reportPath}`);
        } catch (error) {
          this.log.warn(
            `Failed to generate local HTML report: ${error instanceof Error ? error.message : String(error)}`
          );
        }
      }
    } else if (this.coverageEnabled && !this.coverageMerger?.hasCoverage) {
      this.log.warn(
        'Coverage enabled but no data was collected. Ensure your app is instrumented ' +
          'with Istanbul (babel-plugin-istanbul) and tests use { test } from @testdino/playwright'
      );
    }

    const event: TestRunEndEvent = {
      type: 'run:end',
      runId: this.runId,
      ...this.getEventMetadata(),

      // Run Status
      status: result.status as 'passed' | 'failed' | 'timedout' | 'interrupted',

      // Timing
      duration: result.duration,
      startTime: result.startTime.getTime(),

      // Shard information
      shard: this.shardInfo,
    };

    // Flush any remaining buffered events first
    try {
      await this.buffer!.flush();
    } catch (error) {
      this.log.error(`Failed to flush buffered events: ${error}`);
    }

    // Deliver run:end via delivery manager (Kafka primary, HTTP fallback)
    if (this.deliveryManager) {
      try {
        await this.deliveryManager.send(event);
        this.log.success('run:end delivered');
      } catch (error) {
        this.log.error(`Failed to deliver run:end event: ${error instanceof Error ? error.message : String(error)}`);
      }
    }

    // Print comprehensive run summary
    const summaryData: RunSummaryData = {
      runId: this.runId,
      runMetadata: this.runMetadata,
      testCounts: this.testCounts,
      totalTests: this.totalTests,
      workerCount: this.workerCount,
      projectNames: this.projectNames,
      shardInfo: this.shardInfo,
      lastCoverageEvent: this.lastCoverageEvent,
    };
    await this.log.printRunSummary(result, summaryData);

    // Check if coverage thresholds were not met
    if (this.coverageThresholdFailed && this.lastCoverageEvent) {
      const failures = this.checkCoverageThresholds(this.lastCoverageEvent.summary);
      this.log.error('Coverage thresholds not met:');
      for (const msg of failures) {
        this.log.error(`  ${msg}`);
      }
      await this.kafkaProducer?.close();
      this.removeSignalHandlers();
      return { status: 'failed' };
    }

    // Close connections and remove signal handlers
    await this.kafkaProducer?.close();
    this.removeSignalHandlers();
  }

  /**
   * Called on global errors
   */
  async onError(error: TestError): Promise<void> {
    if (!this.initPromise || this.initFailed) return;

    const event: TestRunErrorEvent = {
      type: 'run:error',
      runId: this.runId,
      ...this.getEventMetadata(),

      // Error Information (with cause support)
      error: this.extractGlobalError(error),
    };

    await this.buffer!.add(event);
  }

  /**
   * Called when standard output is produced in worker process
   */
  async onStdOut(chunk: string | Buffer, test?: TestCase, result?: TestResult): Promise<void> {
    if (!this.initPromise || this.initFailed) return;

    const { text, truncated } = this.truncateChunk(chunk);

    const event: TestConsoleOutEvent = {
      type: 'console:out',
      runId: this.runId,
      ...this.getEventMetadata(),

      // Console Output
      text,

      // Test Association (optional)
      testId: test?.id,
      retry: result?.retry,

      // Truncation Indicator
      truncated,
    };

    await this.buffer!.add(event);
  }

  /**
   * Called when standard error is produced in worker process
   */
  async onStdErr(chunk: string | Buffer, test?: TestCase, result?: TestResult): Promise<void> {
    if (!this.initPromise || this.initFailed) return;

    const { text, truncated } = this.truncateChunk(chunk);

    const event: TestConsoleErrEvent = {
      type: 'console:err',
      runId: this.runId,
      ...this.getEventMetadata(),

      // Console Error Output
      text,

      // Test Association (optional)
      testId: test?.id,
      retry: result?.retry,

      // Truncation Indicator
      truncated,
    };

    await this.buffer!.add(event);
  }

  /**
   * Indicates whether this reporter outputs to stdout/stderr
   * Returns false to allow Playwright to add its own terminal output
   */
  printsToStdio(): boolean {
    return false;
  }

  /**
   * Deliver events via Kafka
   */
  private async sendEvents(events: TestEvent[]): Promise<void> {
    if (events.length === 0) return;

    if (this.config.debug) {
      for (const event of events) {
        if (event.type === 'test:begin') {
          const testBeginEvent = event as TestBeginEvent;
          this.log.debug(
            `Sending event type=${event.type} sequence=${event.sequence} runId=${event.runId} testId=${testBeginEvent.testId} retry=${testBeginEvent.retry} parallelIndex=${testBeginEvent.parallelIndex} title=${testBeginEvent.title}`
          );
        } else if (event.type === 'test:end') {
          const testEndEvent = event as TestEndEvent;
          this.log.debug(
            `Sending event type=${event.type} sequence=${event.sequence} runId=${event.runId} testId=${testEndEvent.testId} retry=${testEndEvent.retry} parallelIndex=${testEndEvent.parallelIndex}`
          );
        } else {
          this.log.debug(`Sending event type=${event.type} sequence=${event.sequence} runId=${event.runId}`);
        }
      }
    }

    // Deliver via delivery manager (Kafka primary, HTTP fallback with retry)
    if (this.deliveryManager) {
      try {
        await this.deliveryManager.sendBatch(events);
      } catch (error) {
        this.log.error(`Failed to deliver events: ${error instanceof Error ? error.message : String(error)}`);
        // All delivery channels exhausted — events are lost but tests continue locally.
      }
    }
  }

  /**
   * Get token from config or environment
   */
  private getToken(): string | undefined {
    return this.config.token || process.env.TESTDINO_TOKEN;
  }

  /**
   * Get server URL from config or environment
   */
  private getServerUrl(): string {
    const baseUrl = this.config.serverUrl || process.env.TESTDINO_SERVER_URL || 'https://api.testdino.com';

    // Ensure the URL ends with /api/reporter for CLI endpoints
    return baseUrl.endsWith('/api/reporter') ? baseUrl : `${baseUrl}/api/reporter`;
  }

  /**
   * Print a formatted configuration error with solutions
   */
  private printConfigurationError(message: string, solutions: string[]): void {
    const border = '═'.repeat(70);
    console.error('');
    console.error(border);
    console.error('  ❌ TestDino Reporter Configuration Error');
    console.error(border);
    console.error(`  ${message}`);
    console.error('');
    console.error('  Solutions:');
    solutions.forEach((solution, index) => {
      console.error(`    ${index + 1}. ${solution}`);
    });
    console.error(border);
    console.error('');
  }

  /**
   * Collect metadata for the test run
   */
  private async collectMetadata(playwrightConfig: FullConfig, playwrightSuite: Suite): Promise<RunMetadata> {
    try {
      const metadataCollector = createMetadataCollector(playwrightConfig, playwrightSuite);
      const result = await metadataCollector.collectAll();

      if (result.failureCount > 0) {
        this.log.warn(`${result.failureCount}/${result.results.length} metadata collectors failed`);
      }

      // Build skeleton from suite
      const skeleton = metadataCollector.buildSkeleton(playwrightSuite);

      // Add skeleton to metadata
      return {
        ...result.metadata,
        skeleton,
      };
    } catch (error) {
      this.log.warn(`Metadata collection failed: ${error instanceof Error ? error.message : String(error)}`);
      return {}; // Return empty metadata as fallback
    }
  }

  /**
   * Get next sequence number and current timestamp
   */
  private getEventMetadata() {
    return {
      timestamp: Date.now(),
      sequence: ++this.sequenceNumber,
    };
  }

  /**
   * Extract annotations with optional location information
   */
  private extractAnnotations(annotations: Array<Annotation> | undefined): Array<Annotation> {
    if (!annotations || annotations.length === 0) {
      return [];
    }

    return annotations.map((a) => ({
      type: a.type,
      description: a.description,
    }));
  }

  /**
   * Extract parent suite information for skeleton mapping
   */
  private extractParentSuite(parent: Suite): TestBeginEvent['parentSuite'] {
    return {
      title: parent.title,
      type: parent.type,
      location: parent.location
        ? {
            file: parent.location.file,
            line: parent.location.line,
            column: parent.location.column,
          }
        : undefined,
    };
  }

  /**
   * Extract parent step information for step hierarchy mapping
   */
  private extractParentStep(parent: TestStep): TestStepBeginEvent['parentStep'] {
    return {
      title: parent.title,
      category: parent.category,
      location: parent.location
        ? {
            file: parent.location.file,
            line: parent.location.line,
            column: parent.location.column,
          }
        : undefined,
    };
  }

  /**
   * Extract child steps summary for step:end event
   */
  private extractChildSteps(step: TestStep): TestStepEndEvent['childSteps'] {
    return {
      count: step.steps.length,
      steps: step.steps.map((child) => ({
        title: child.title,
        status: child.error ? 'failed' : 'passed',
      })),
    };
  }

  /**
   * Extract error details from TestError (shared by step:end, test:end, and error events)
   */
  private extractError(error: TestError | undefined): TestStepEndEvent['error'] {
    if (!error) return undefined;

    return {
      message: error.message || String(error),
      stack: error.stack,
      snippet: error.snippet,
      value: error.value,
      location: error.location
        ? {
            file: error.location.file,
            line: error.location.line,
            column: error.location.column,
          }
        : undefined,
    };
  }

  /**
   * Extract global error details with cause support (for error events)
   */
  private extractGlobalError(error: TestError): TestRunErrorEvent['error'] {
    return {
      message: error.message,
      stack: error.stack,
      snippet: error.snippet,
      value: error.value,
      location: error.location
        ? {
            file: error.location.file,
            line: error.location.line,
            column: error.location.column,
          }
        : undefined,
      // Handle nested error cause (v1.49+)
      cause: error.cause
        ? {
            message: error.cause.message,
            stack: error.cause.stack,
            snippet: error.cause.snippet,
            value: error.cause.value,
            location: error.cause.location
              ? {
                  file: error.cause.location.file,
                  line: error.cause.location.line,
                  column: error.cause.location.column,
                }
              : undefined,
          }
        : undefined,
    };
  }

  /**
   * Truncate console chunk to max size and convert Buffer to string
   */
  private truncateChunk(chunk: string | Buffer): { text: string; truncated?: boolean } {
    // Convert Buffer to string (UTF-8)
    let convertedText: string;
    if (Buffer.isBuffer(chunk)) {
      convertedText = chunk.toString('utf-8');
    } else {
      convertedText = chunk;
    }

    // Check if truncation is needed
    if (convertedText.length > MAX_CONSOLE_CHUNK_SIZE) {
      return {
        text: convertedText.substring(0, MAX_CONSOLE_CHUNK_SIZE) + '\n[truncated]',
        truncated: true,
      };
    }

    return { text: convertedText };
  }

  /**
   * Extract attachment metadata for step:end event
   */
  private extractAttachments(step: TestStep): TestStepEndEvent['attachments'] {
    return step.attachments.map((a) => ({
      name: a.name,
      contentType: a.contentType,
      path: a.path, // undefined for in-memory attachments
    }));
  }

  /**
   * Extract steps summary for test:end event
   */
  private extractTestStepsSummary(result: TestResult): TestEndEvent['steps'] {
    return {
      total: result.steps.length,
      passed: result.steps.filter((s) => !s.error).length,
      failed: result.steps.filter((s) => s.error).length,
    };
  }

  /**
   * Extract console output for test:end event
   */
  private extractConsoleOutput(output: Array<string | Buffer>): string[] {
    return output.map((item) => (typeof item === 'string' ? item : item.toString()));
  }

  /**
   * Check if this is a duplicate instance of TestdinoReporter
   * This happens when the CLI injects our reporter via --reporter flag,
   * but the user already has TestdinoReporter configured in playwright.config
   *
   * @param reporters - The resolved reporters array from FullConfig
   * @returns true if there are multiple TestdinoReporter instances, false otherwise
   */
  private isDuplicateInstance(reporters: unknown[]): boolean {
    const count = this.countTestdinoReporters(reporters);

    // If count > 1, it means we have both:
    // - One from playwright.config (user's manual config)
    // - One from CLI injection (our --reporter flag)
    // The config-based instance should handle reporting, so we exit
    return count > 1;
  }

  /**
   * Count how many TestdinoReporter instances are in the reporters array
   *
   * @param reporters - The resolved reporters array from FullConfig
   * @returns Number of TestdinoReporter instances found
   */
  private countTestdinoReporters(reporters: unknown): number {
    // Guard against undefined or non-array reporters
    if (!reporters || !Array.isArray(reporters)) {
      return 0;
    }

    let count = 0;

    for (const reporter of reporters) {
      // Reporters can be in multiple formats:
      // - ['@testdino/playwright'] - string in array
      // - ['@testdino/playwright', options] - string with options
      // - Class instance (when instantiated with new)

      if (Array.isArray(reporter) && reporter.length > 0) {
        const reporterName = reporter[0];
        if (this.isTestdinoReporter(reporterName)) {
          count++;
        }
      }
    }

    return count;
  }

  /**
   * Check if a reporter name/path matches TestdinoReporter
   *
   * @param value - Reporter name, path, or class reference
   * @returns true if this is our reporter, false otherwise
   */
  private isTestdinoReporter(value: unknown): boolean {
    if (typeof value !== 'string') {
      return false;
    }

    // Check various forms our reporter might appear as:
    // - '@testdino/playwright' (npm package name)
    // - 'TestdinoReporter' (class name)
    // - Path ending with 'testdino-playwright'
    return (
      value.includes('@testdino/playwright') ||
      value.includes('TestdinoReporter') ||
      value.endsWith('testdino-playwright')
    );
  }

  /**
   * Register signal handlers for graceful shutdown on interruption
   */
  private registerSignalHandlers(): void {
    // Use a wrapper that properly handles async operations
    // Node.js signal handlers don't wait for async operations,
    // so we need to prevent immediate exit and handle manually
    this.sigintHandler = () => {
      // Remove handler immediately to prevent duplicate signals during shutdown
      if (this.sigintHandler) {
        process.removeListener('SIGINT', this.sigintHandler);
      }
      if (this.sigtermHandler) {
        process.removeListener('SIGTERM', this.sigtermHandler);
      }

      this.handleInterruption('SIGINT', 130);
    };

    this.sigtermHandler = () => {
      // Remove handler immediately to prevent duplicate signals during shutdown
      if (this.sigintHandler) {
        process.removeListener('SIGINT', this.sigintHandler);
      }
      if (this.sigtermHandler) {
        process.removeListener('SIGTERM', this.sigtermHandler);
      }

      this.handleInterruption('SIGTERM', 143);
    };

    process.on('SIGINT', this.sigintHandler);
    process.on('SIGTERM', this.sigtermHandler);
  }

  /**
   * Remove signal handlers (called on normal completion or after handling interruption)
   */
  private removeSignalHandlers(): void {
    if (this.sigintHandler) {
      process.removeListener('SIGINT', this.sigintHandler);
    }
    if (this.sigtermHandler) {
      process.removeListener('SIGTERM', this.sigtermHandler);
    }
  }

  /**
   * Handle process interruption by sending run:end event with interrupted status
   * @param signal - The signal that triggered the interruption (SIGINT or SIGTERM)
   * @param exitCode - The exit code to use when exiting
   */
  private handleInterruption(signal: string, exitCode: number): void {
    // Prevent duplicate handling
    if (this.isShuttingDown) return;
    this.isShuttingDown = true;

    this.log.warn(`Received ${signal}, sending interruption event...`);

    if (!this.initPromise) {
      // Init never started, just exit
      process.exit(exitCode);
    }

    // Wait up to 2000ms for pending test:end events to finish (matches send timeout)
    // This allows time for in-progress uploads to complete during graceful shutdown
    const waitForPending = async () => {
      if (this.pendingTestEndPromises.size > 0) {
        try {
          await Promise.race([
            Promise.allSettled(Array.from(this.pendingTestEndPromises)),
            this.timeoutPromise(2000, 'Pending events timeout'),
          ]);
        } catch {
          // Timeout expected, continue with shutdown
        }
      }
    };

    // Create interruption event
    const event: TestRunEndEvent = {
      type: 'run:end',
      runId: this.runId,
      ...this.getEventMetadata(),
      status: 'interrupted',
      duration: this.runStartTime ? Date.now() - this.runStartTime : 0,
      startTime: this.runStartTime ?? Date.now(),
      shard: this.shardInfo,
    };

    // Keep event loop alive with interval - CRITICAL for ensuring async operations complete
    const keepAlive = setInterval(() => {
      // Empty interval to keep process alive
    }, 100);

    // Hard timeout to force exit if send hangs
    const forceExitTimer = setTimeout(() => {
      clearInterval(keepAlive);
      this.log.error('Force exit - send timeout exceeded');
      process.exit(exitCode);
    }, 3000); // 3 second hard limit

    // Send interruption event directly (bypass buffer to avoid flush delays)
    const sendAndExit = async () => {
      try {
        // Wait briefly for pending test:end events (best effort)
        await waitForPending();

        // Send directly without buffering for speed
        await Promise.race([this.sendInterruptionEvent(event), this.timeoutPromise(2500, 'Send timeout')]);

        this.log.success('Interruption event sent');
      } catch (error) {
        const errorMsg = error instanceof Error ? error.message : String(error);
        this.log.error(`Failed to send interruption event: ${errorMsg}`);
      } finally {
        // Clean up
        clearTimeout(forceExitTimer);
        clearInterval(keepAlive);
        process.exit(exitCode);
      }
    };

    // Execute
    sendAndExit().catch(() => {
      clearTimeout(forceExitTimer);
      clearInterval(keepAlive);
      process.exit(exitCode);
    });
  }

  /**
   * Send interruption event directly without buffering
   * Uses optimized path for speed during shutdown
   */
  private async sendInterruptionEvent(event: TestRunEndEvent): Promise<void> {
    if (this.kafkaProducer?.isConnected) {
      await this.kafkaProducer.send(event);
      await this.kafkaProducer.close();
    }
  }

  /**
   * Create a promise that rejects after a timeout
   * @param ms - Timeout in milliseconds
   * @param message - Error message for timeout
   */
  private timeoutPromise(ms: number, message: string): Promise<never> {
    return new Promise((_, reject) => setTimeout(() => reject(new Error(message)), ms));
  }

  /**
   * Upload attachments and return with Azure URLs
   * If uploads disabled or failed, returns attachments with local paths
   */
  private async uploadAttachments(
    attachments: Array<{ name: string; contentType: string; path?: string; body?: Buffer }>,
    testId: string
  ): Promise<Array<{ name: string; contentType: string; path?: string }>> {
    // If uploads not enabled or no uploader, return original attachments
    if (!this.artifactsEnabled || !this.artifactUploader) {
      return attachments.map((a) => ({
        name: a.name,
        contentType: a.contentType,
        path: a.path,
      }));
    }

    // Filter to file-based attachments only (with path)
    const fileAttachments: AttachmentForUpload[] = attachments
      .filter((a): a is { name: string; contentType: string; path: string } => !!a.path)
      .map((a) => ({
        name: a.name,
        contentType: a.contentType,
        path: a.path,
      }));

    // If no file attachments, return original
    if (fileAttachments.length === 0) {
      return attachments.map((a) => ({
        name: a.name,
        contentType: a.contentType,
        path: a.path,
      }));
    }

    // Upload files in parallel
    const uploadResults = await this.artifactUploader.uploadAll(fileAttachments, testId);

    // Create a map of upload results by name
    const uploadMap = new Map<string, UploadResult>();
    for (const result of uploadResults) {
      uploadMap.set(result.name, result);
    }

    // Map attachments with Azure URLs where upload succeeded
    return attachments.map((a) => {
      const uploadResult = uploadMap.get(a.name);
      if (uploadResult?.success && uploadResult.uploadUrl) {
        // Replace local path with Azure URL
        return {
          name: a.name,
          contentType: a.contentType,
          path: uploadResult.uploadUrl,
        };
      }
      // Keep original path if upload failed or not applicable
      return {
        name: a.name,
        contentType: a.contentType,
        path: a.path,
      };
    });
  }

  /**
   * Walk up the suite hierarchy to find the project name for a test.
   */
  private getProjectName(test: TestCase): string | undefined {
    let suite: Suite | undefined = test.parent;
    while (suite) {
      const project = suite.project();
      if (project) {
        return project.name || project.use?.defaultBrowserType || 'default';
      }
      suite = suite.parent;
    }
    return undefined;
  }

  /**
   * Extract coverage fragment from test result attachments and merge incrementally.
   * The fixture attaches coverage as an in-memory JSON attachment named 'testdino-coverage'.
   */
  private extractCoverageFromResult(result: TestResult, merger: CoverageMerger): void {
    const coverageAttachment = result.attachments.find((a) => a.name === 'testdino-coverage');

    if (!coverageAttachment?.body) return;

    try {
      const fragment: CoverageFragment = JSON.parse(coverageAttachment.body.toString());
      merger.addFragment(fragment);
    } catch (error) {
      this.log.debug(
        `Malformed coverage attachment, skipping: ${error instanceof Error ? error.message : String(error)}`
      );
    }
  }

  /**
   * Build a coverage:data event from the merged coverage data.
   *
   * Non-sharded runs: summary + per-file metrics only (small payload).
   * Sharded runs: also includes compact hit counts for server-side cross-shard merging.
   */
  private buildCoverageEvent(merger: CoverageMerger): CoverageDataEvent {
    const rootDir = this.runMetadata?.playwright?.rootDir || process.cwd();
    const summary = merger.computeSummary();
    const files = merger.computeFileCoverage(rootDir);
    const isSharded = !!this.shardInfo;

    if (files.length > COVERAGE_FILE_COUNT_WARNING) {
      this.log.warn(
        `Coverage includes ${files.length} files — consider using coverage.include/exclude to reduce scope`
      );
    }

    const event: CoverageDataEvent = {
      type: 'coverage:data',
      runId: this.runId,
      ...this.getEventMetadata(),
      summary,
      files,
      metadata: {
        instrumentationType: 'istanbul',
        fileCount: files.length,
        sharded: isSharded,
      },
    };

    // For sharded runs, include compact hit counts for server-side merging
    if (isSharded) {
      const coverageMapJSON = merger.toJSON();
      event.compactCounts = extractCompactCounts(coverageMapJSON, rootDir);
      event.shard = this.shardInfo;
    }

    return event;
  }

  /**
   * Check coverage against configured thresholds.
   * Returns an array of failure messages (empty if all thresholds pass).
   */
  private checkCoverageThresholds(summary: import('../types/index.js').CoverageSummary): string[] {
    const thresholds = this.config.coverage?.thresholds;
    if (!thresholds) return [];

    const failures: string[] = [];
    const check = (name: string, actual: number, threshold: number | undefined) => {
      if (threshold !== undefined && actual < threshold) {
        failures.push(`${name}: ${actual.toFixed(2)}% < ${threshold}%`);
      }
    };

    check('Statements', summary.statements.pct, thresholds.statements);
    check('Branches', summary.branches.pct, thresholds.branches);
    check('Functions', summary.functions.pct, thresholds.functions);
    check('Lines', summary.lines.pct, thresholds.lines);

    return failures;
  }
}
