/**
 * Git metadata collector
 * Collects git repository information using git commands
 */

import { readFile } from 'fs/promises';
import { BaseMetadataCollector } from './base.js';
import type { GitMetadata, PRMetadata } from './types.js';

// Dynamic import for execa (ESM-only package, needs dynamic import in CJS context)
let execaPromise: Promise<typeof import('execa').execa> | null = null;

/**
 * Dynamically import execa (ESM-only package) for CJS compatibility only once per process using memoization.
 *
 * @returns Promise resolving to the execa function
 * @throws Error if execa cannot be imported
 */
async function getExeca(): Promise<typeof import('execa').execa> {
  if (!execaPromise) {
    execaPromise = import('execa')
      .then((m) => m.execa)
      .catch((error) => {
        console.error('Failed to import execa:', error.message);
        // Reset so the next call can retry the import
        execaPromise = null;
        throw new Error('Failed to load execa. Ensure execa is installed: npm install execa');
      });
  }
  return execaPromise;
}

/**
 * Minimal GitHub event data interface for type safety
 */
interface GitHubEventData {
  pull_request?: {
    title?: unknown;
    number?: unknown;
    state?: unknown;
    head?: { ref?: unknown; sha?: unknown };
    base?: { ref?: unknown };
    user?: { login?: unknown };
    labels?: Array<{ name?: unknown }>;
    merged?: unknown;
    mergeable?: unknown;
    merge_commit_sha?: unknown;
  };
}

/**
 * Resolved GitHub author information for deduplication and canonical naming
 */
interface GitHubAuthorInfo {
  authorId: string;
  authorLogin?: string;
}

export interface GitCollectorOptions {
  /**
   * Timeout for git commands in milliseconds
   * @default 3000
   */
  timeout?: number;

  /**
   * Working directory for git commands
   * @default process.cwd()
   */
  cwd?: string;
}

/**
 * Collects git repository metadata
 */
export class GitMetadataCollector extends BaseMetadataCollector<GitMetadata> {
  private options: Required<GitCollectorOptions>;

  constructor(options: GitCollectorOptions = {}) {
    super('git');
    this.options = {
      timeout: options.timeout || 3000,
      cwd: options.cwd || process.cwd(),
    };
  }

  /**
   * Collect git metadata
   */
  protected async collectMetadata(): Promise<GitMetadata> {
    // Fix git ownership issues in CI containers
    await this.configureGitForCI();

    // Check if we're in a git repository
    const isGitRepo = await this.isGitRepository();
    if (!isGitRepo) {
      return this.getEmptyMetadata();
    }

    // Collect all git metadata in parallel using Promise.allSettled for error isolation
    const results = await Promise.allSettled([
      this.getBranch(),
      this.getCommitHash(),
      this.getCommitMessage(),
      this.getAuthorName(),
      this.getAuthorEmail(),
      this.getCommitTimestamp(),
      this.getRepoUrl(),
      this.isDirtyWorkingTree(),
    ]);

    // Extract values, using undefined for rejected promises
    const extractedValues = results.map((r) => (r.status === 'fulfilled' ? r.value : undefined));

    // Variables that may be reassigned in PR context below
    let branch = extractedValues[0] as string | undefined;
    let hash = extractedValues[1] as string | undefined;
    let message = extractedValues[2] as string | undefined;
    let author = extractedValues[3] as string | undefined;
    let email = extractedValues[4] as string | undefined;
    let timestamp = extractedValues[5] as string | undefined;

    // Variables that are never reassigned
    const repoUrl = extractedValues[6] as string | undefined;
    const isDirty = extractedValues[7] as boolean | undefined;

    // Handle PR context — override merge commit data with real PR data
    let prMetadata: PRMetadata | undefined;

    if (process.env.GITHUB_EVENT_NAME === 'pull_request') {
      const eventData = await this.readGitHubEventFile();

      if (eventData?.pull_request) {
        prMetadata = this.extractPRMetadata(eventData);

        // Override branch with real source branch
        const headRef = process.env.GITHUB_HEAD_REF;
        if (this.isNonEmptyString(headRef)) {
          branch = headRef;
        }

        // Override commit data with real PR head commit
        const headSha = eventData.pull_request.head?.sha;
        if (this.isNonEmptyString(headSha)) {
          hash = headSha;
          const realCommit = await this.getCommitInfoFromSha(headSha);
          if (realCommit) {
            message = realCommit.message ?? message;
            author = realCommit.author ?? author;
            email = realCommit.email ?? email;
            timestamp = realCommit.timestamp ?? timestamp;
          }
        }
      }
    }

    // Resolve GitHub author info: numeric ID for deduplication, login for canonical name
    const githubAuthor = await this.resolveGitHubAuthor(hash);

    return {
      branch,
      commit: {
        hash,
        message,
        author: githubAuthor.authorLogin || author,
        authorId: githubAuthor.authorId,
        email,
        timestamp,
        isDirty,
      },
      repository: {
        name: this.extractRepoName(repoUrl),
        url: repoUrl,
      },
      ...(prMetadata ? { pr: prMetadata } : {}),
    };
  }

  /**
   * Get empty metadata
   */
  protected getEmptyMetadata(): GitMetadata {
    return {};
  }

  /**
   * Configure git for CI environments
   * Fixes "dubious ownership" errors when workspace is mounted with different ownership
   */
  private async configureGitForCI(): Promise<void> {
    const isCI = process.env.CI === 'true' || process.env.GITHUB_ACTIONS === 'true';
    if (!isCI) return;

    try {
      const execa = await getExeca();
      await execa('git', ['config', '--global', '--add', 'safe.directory', this.options.cwd], {
        timeout: this.options.timeout,
        reject: true,
      });
    } catch {
      // Silently continue — this is a best-effort fix
    }
  }

  /**
   * Read and parse the GitHub Actions event file
   */
  private async readGitHubEventFile(): Promise<GitHubEventData | undefined> {
    const eventPath = process.env.GITHUB_EVENT_PATH;
    if (!eventPath) return undefined;

    try {
      const content = await this.withTimeout(
        readFile(eventPath, 'utf-8'),
        this.options.timeout,
        'GitHub event file read'
      );
      return this.safeJsonParse<GitHubEventData>(content, {});
    } catch (error) {
      console.warn(
        '⚠️  TestDino: Failed to read GitHub event data:',
        error instanceof Error ? error.message : String(error)
      );
      return undefined;
    }
  }

  /**
   * Extract PR metadata from GitHub event data
   */
  private extractPRMetadata(eventData: GitHubEventData): PRMetadata | undefined {
    const pullRequest = eventData?.pull_request;
    if (!pullRequest) return undefined;

    const prMetadata: PRMetadata = {};

    // Basic PR information
    if (this.isNonEmptyString(pullRequest.title)) {
      prMetadata.title = pullRequest.title;
    }

    if (typeof pullRequest.number === 'number') {
      prMetadata.number = pullRequest.number;
    }

    if (this.isNonEmptyString(pullRequest.state)) {
      prMetadata.status = pullRequest.state;
    }

    // Build PR URL
    const serverUrl = process.env.GITHUB_SERVER_URL;
    const repository = process.env.GITHUB_REPOSITORY;
    if (prMetadata.number && serverUrl && repository) {
      prMetadata.url = `${serverUrl}/${repository}/pull/${prMetadata.number}`;
    }

    // Branch information
    if (pullRequest.head?.ref && this.isNonEmptyString(pullRequest.head.ref)) {
      prMetadata.branch = pullRequest.head.ref;
    }

    if (pullRequest.base?.ref && this.isNonEmptyString(pullRequest.base.ref)) {
      prMetadata.targetBranch = pullRequest.base.ref;
    }

    // Author information
    if (pullRequest.user?.login && this.isNonEmptyString(pullRequest.user.login)) {
      prMetadata.author = pullRequest.user.login;
    }

    // Labels
    if (Array.isArray(pullRequest.labels) && pullRequest.labels.length > 0) {
      const labels = pullRequest.labels
        .map((label) => label?.name)
        .filter((name): name is string => this.isNonEmptyString(name));

      if (labels.length > 0) {
        prMetadata.labels = labels;
      }
    }

    // Merge status
    if (typeof pullRequest.merged === 'boolean') {
      prMetadata.merged = pullRequest.merged;
    }

    if (typeof pullRequest.mergeable === 'boolean') {
      prMetadata.mergeable = pullRequest.mergeable;
    }

    if (this.isNonEmptyString(pullRequest.merge_commit_sha)) {
      prMetadata.mergeCommitSha = pullRequest.merge_commit_sha;
    }

    // Return undefined if no meaningful data was extracted
    const hasData = Object.keys(prMetadata).length > 0;
    return hasData ? prMetadata : undefined;
  }

  /**
   * Get commit details for a specific SHA using git show
   * Used to resolve real commit data in PR context (instead of merge commit)
   */
  private async getCommitInfoFromSha(sha: string): Promise<
    | {
        message?: string;
        author?: string;
        email?: string;
        timestamp?: string;
      }
    | undefined
  > {
    try {
      const result = await this.execGit(['show', '-s', '--format=%s%n%an%n%ae%n%aI', sha]);
      const lines = result.split('\n');
      if (lines.length < 4) return undefined;

      return {
        message: this.isNonEmptyString(lines[0]) ? lines[0] : undefined,
        author: this.isNonEmptyString(lines[1]) ? lines[1] : undefined,
        email: this.isNonEmptyString(lines[2]) ? lines[2] : undefined,
        timestamp: this.isNonEmptyString(lines[3]) ? lines[3] : undefined,
      };
    } catch (error) {
      console.warn(
        '⚠️  TestDino: Failed to get commit info from SHA:',
        error instanceof Error ? error.message : String(error)
      );
      return undefined;
    }
  }

  /**
   * Resolve GitHub author info via the Commits API
   * Only runs on GitHub Actions where GITHUB_REPOSITORY is available
   */
  private async resolveGitHubAuthor(commitHash: string | undefined): Promise<GitHubAuthorInfo> {
    const empty: GitHubAuthorInfo = { authorId: '' };

    if (process.env.GITHUB_ACTIONS !== 'true') {
      return empty;
    }

    if (!commitHash) {
      return empty;
    }

    const repository = process.env.GITHUB_REPOSITORY;
    if (!repository) {
      return empty;
    }

    const url = `https://api.github.com/repos/${repository}/commits/${commitHash}`;

    try {
      const headers: Record<string, string> = {
        Accept: 'application/vnd.github.v3+json',
        'User-Agent': 'testdino-playwright',
      };

      const token = process.env.GITHUB_TOKEN;
      if (token) {
        headers.Authorization = `token ${token}`;
      }

      const response = await this.withTimeout(fetch(url, { headers }), this.options.timeout, 'GitHub Commits API');

      if (!response.ok) {
        return empty;
      }

      const data = (await response.json()) as {
        author?: { id?: number; login?: string } | null;
      };

      if (data?.author?.id) {
        const authorId = String(data.author.id);
        const authorLogin = this.isNonEmptyString(data.author.login) ? data.author.login : undefined;
        return { authorId, authorLogin };
      }

      return this.resolveGitHubAuthorFromActor();
    } catch (error) {
      console.warn(
        '⚠️  TestDino: Failed to resolve GitHub author from Commits API:',
        error instanceof Error ? error.message : String(error)
      );
      return this.resolveGitHubAuthorFromActor();
    }
  }

  /**
   * Fallback: resolve GitHub author info from GITHUB_ACTOR via the Users API
   */
  private async resolveGitHubAuthorFromActor(): Promise<GitHubAuthorInfo> {
    const actor = process.env.GITHUB_ACTOR;
    if (!actor) {
      return { authorId: '' };
    }

    const url = `https://api.github.com/users/${actor}`;

    try {
      const response = await this.withTimeout(
        fetch(url, {
          headers: {
            Accept: 'application/vnd.github.v3+json',
            'User-Agent': 'testdino-playwright',
          },
        }),
        this.options.timeout,
        'GitHub Users API'
      );

      if (!response.ok) {
        return { authorId: '' };
      }

      const data = (await response.json()) as {
        id?: number;
        login?: string;
      };

      const authorId = data?.id ? String(data.id) : '';
      const authorLogin = this.isNonEmptyString(data?.login) ? data.login : actor;

      return { authorId, authorLogin };
    } catch (error) {
      console.warn(
        '⚠️  TestDino: Failed to resolve GitHub author from GITHUB_ACTOR:',
        error instanceof Error ? error.message : String(error)
      );
      return { authorId: '' };
    }
  }

  /**
   * Check if current directory is a git repository
   */
  private async isGitRepository(): Promise<boolean> {
    try {
      await this.execGit(['rev-parse', '--git-dir']);
      return true;
    } catch {
      return false;
    }
  }

  /**
   * Get current branch name
   * Uses: git rev-parse --abbrev-ref HEAD
   */
  private async getBranch(): Promise<string | undefined> {
    try {
      const result = await this.execGit(['rev-parse', '--abbrev-ref', 'HEAD']);
      return this.isNonEmptyString(result) ? result : undefined;
    } catch {
      return undefined;
    }
  }

  /**
   * Get current commit hash (full SHA)
   * Uses: git rev-parse HEAD
   */
  private async getCommitHash(): Promise<string | undefined> {
    try {
      const result = await this.execGit(['rev-parse', 'HEAD']);
      return this.isNonEmptyString(result) ? result : undefined;
    } catch {
      return undefined;
    }
  }

  /**
   * Get commit message of current HEAD
   * Uses: git log -1 --pretty=format:%s
   */
  private async getCommitMessage(): Promise<string | undefined> {
    try {
      const result = await this.execGit(['log', '-1', '--pretty=format:%s']);
      return this.isNonEmptyString(result) ? result : undefined;
    } catch {
      return undefined;
    }
  }

  /**
   * Get commit author name
   * Uses: git log -1 --pretty=format:%an
   */
  private async getAuthorName(): Promise<string | undefined> {
    try {
      const result = await this.execGit(['log', '-1', '--pretty=format:%an']);
      return this.isNonEmptyString(result) ? result : undefined;
    } catch {
      return undefined;
    }
  }

  /**
   * Get commit author email
   * Uses: git log -1 --pretty=format:%ae
   */
  private async getAuthorEmail(): Promise<string | undefined> {
    try {
      const result = await this.execGit(['log', '-1', '--pretty=format:%ae']);
      return this.isNonEmptyString(result) ? result : undefined;
    } catch {
      return undefined;
    }
  }

  /**
   * Get commit timestamp (ISO format)
   * Uses: git log -1 --pretty=format:%aI
   */
  private async getCommitTimestamp(): Promise<string | undefined> {
    try {
      const result = await this.execGit(['log', '-1', '--pretty=format:%aI']);
      return this.isNonEmptyString(result) ? result : undefined;
    } catch {
      return undefined;
    }
  }

  /**
   * Get remote origin URL
   * Uses: git config --get remote.origin.url
   */
  private async getRepoUrl(): Promise<string | undefined> {
    try {
      const result = await this.execGit(['config', '--get', 'remote.origin.url']);
      return this.isNonEmptyString(result) ? result : undefined;
    } catch {
      return undefined;
    }
  }

  /**
   * Check if working tree has uncommitted changes
   * Uses: git status --porcelain
   * Returns true if there are any changes (staged, unstaged, or untracked)
   */
  private async isDirtyWorkingTree(): Promise<boolean | undefined> {
    try {
      const result = await this.execGit(['status', '--porcelain']);
      // If output is non-empty, there are changes
      return result.trim().length > 0;
    } catch {
      return undefined;
    }
  }

  /**
   * Extract repository name from remote URL
   * e.g., "https://github.com/user/repo.git" → "repo"
   */
  private extractRepoName(repoUrl: string | undefined): string | undefined {
    if (!repoUrl) return undefined;
    return repoUrl.split('/').pop()?.replace('.git', '') || undefined;
  }

  /**
   * Execute git command with timeout
   */
  private async execGit(args: string[]): Promise<string> {
    const execa = await getExeca();
    const { stdout } = await this.withTimeout(
      execa('git', args, {
        cwd: this.options.cwd,
        timeout: this.options.timeout,
        reject: true,
      }),
      this.options.timeout,
      `git ${args.join(' ')}`
    );

    return stdout.trim();
  }
}
