/**
 * Metadata collection main exports and aggregator
 */

import type {
  MetadataCollectionOptions,
  MetadataCollectionResult,
  MetadataCollectionSummary,
  CompleteMetadata,
  GitMetadata,
  CIMetadata,
  SystemMetadata,
  PlaywrightMetadata,
} from './types.js';
import { GitMetadataCollector } from './git.js';
import { CIMetadataCollector } from './ci.js';
import { SystemMetadataCollector } from './system.js';
import { PlaywrightMetadataCollector } from './playwright.js';

/**
 * Default metadata collection options
 * @internal
 */
const DEFAULT_METADATA_OPTIONS: Required<MetadataCollectionOptions> = {
  timeout: 5000,
  debug: false,
};

/**
 * Playwright FullConfig interface (minimal subset for metadata collection)
 */
interface PlaywrightFullConfig {
  fullyParallel?: boolean;
  workers?: number;
  shard?: {
    current: number;
    total: number;
  } | null;
  projects?: Array<{
    name?: string;
  }>;
}

/**
 * Playwright Suite interface (minimal subset for skeleton building)
 */
interface PlaywrightSuite {
  title: string;
  type: 'root' | 'project' | 'file' | 'describe';
  location?: {
    file: string;
    line: number;
    column: number;
  };
  suites: PlaywrightSuite[];
  tests: PlaywrightTestCase[];
  allTests(): PlaywrightTestCase[];
}

/**
 * Playwright TestCase interface (minimal subset for skeleton building)
 */
interface PlaywrightTestCase {
  id: string;
  title: string;
  location: {
    file: string;
    line: number;
    column: number;
  };
  tags: string[];
  expectedStatus: 'passed' | 'failed' | 'timedOut' | 'skipped' | 'interrupted';
  annotations: Array<{
    type: string;
    description?: string;
  }>;
}

/**
 * Main metadata aggregator class
 * Orchestrates collection from all metadata collectors
 */
export class MetadataAggregator {
  private options: Required<MetadataCollectionOptions>;
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  private collectors: Array<{ collectWithResult: () => Promise<MetadataCollectionResult<any>> }> = [];
  private playwrightCollector?: PlaywrightMetadataCollector;

  constructor(options: MetadataCollectionOptions = {}) {
    this.options = { ...DEFAULT_METADATA_OPTIONS, ...options };
  }

  /**
   * Register a metadata collector
   */
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  registerCollector(collector: { collectWithResult: () => Promise<MetadataCollectionResult<any>> }): void {
    this.collectors.push(collector);

    // Keep reference to PlaywrightMetadataCollector for skeleton building
    if (collector instanceof PlaywrightMetadataCollector) {
      this.playwrightCollector = collector;
    }
  }

  /**
   * Build skeleton from Suite (if PlaywrightMetadataCollector is registered with a suite)
   */
  buildSkeleton(suite: PlaywrightSuite): CompleteMetadata['skeleton'] {
    if (!this.playwrightCollector) {
      return undefined;
    }

    return this.playwrightCollector.buildSkeleton(suite);
  }

  /**
   * Collect metadata from all registered collectors
   * Uses Promise.allSettled for error isolation
   */
  async collectAll(): Promise<MetadataCollectionSummary> {
    const startTime = Date.now();

    // Collect from all collectors in parallel with error isolation
    const settledResults = await Promise.allSettled(
      this.collectors.map((collector) =>
        this.withTimeout(collector.collectWithResult(), this.options.timeout, 'Metadata collection')
      )
    );

    // Process results
    const results: MetadataCollectionResult[] = [];
    const metadata: CompleteMetadata = {};

    for (const settledResult of settledResults) {
      if (settledResult.status === 'fulfilled') {
        const result = settledResult.value;
        results.push(result);

        // Aggregate metadata by collector type
        this.aggregateMetadata(metadata, result);
      } else {
        // Handle rejected promises (shouldn't happen due to error handling in collectors)
        const error = settledResult.reason;
        console.warn('⚠️  TestDino: Metadata collector promise rejected:', error);

        results.push({
          data: {},
          success: false,
          error: error instanceof Error ? error.message : String(error),
          duration: 0,
          collector: 'unknown',
        });
      }
    }

    const totalDuration = Date.now() - startTime;
    const successCount = results.filter((r) => r.success).length;
    const failureCount = results.length - successCount;

    return {
      metadata,
      results,
      totalDuration,
      successCount,
      failureCount,
    };
  }

  /**
   * Aggregate individual collector results into complete metadata
   */
  private aggregateMetadata(metadata: CompleteMetadata, result: MetadataCollectionResult): void {
    const { collector, data } = result;

    switch (collector) {
      case 'git':
        metadata.git = data as GitMetadata;
        break;
      case 'ci':
        metadata.ci = data as CIMetadata;
        break;
      case 'system':
        metadata.system = data as SystemMetadata;
        break;
      case 'playwright':
        metadata.playwright = data as PlaywrightMetadata;
        break;
      default:
        if (this.options.debug) {
          console.warn(`⚠️  TestDino: Unknown metadata collector: ${collector}`);
        }
    }
  }

  /**
   * Utility method to run operation with timeout
   */
  private async withTimeout<T>(promise: Promise<T>, timeoutMs: number, operation: string): Promise<T> {
    const timeoutPromise = new Promise<never>((_, reject) => {
      setTimeout(() => {
        reject(new Error(`${operation} timed out after ${timeoutMs}ms`));
      }, timeoutMs);
    });

    return Promise.race([promise, timeoutPromise]);
  }
}

// Re-export types
export type {
  MetadataCollectionOptions,
  MetadataCollectionResult,
  MetadataCollectionSummary,
  CompleteMetadata,
  GitMetadata,
  CIMetadata,
  SystemMetadata,
  PlaywrightMetadata,
  PRMetadata,
  ShardMetadata,
  MetadataCollector,
  RunSkeleton,
  SkeletonSuite,
  SkeletonTest,
} from './types.js';

// Re-export base class
export { BaseMetadataCollector } from './base.js';

// Re-export collectors
export { GitMetadataCollector } from './git.js';
export { CIMetadataCollector } from './ci.js';
export { SystemMetadataCollector } from './system.js';
export { PlaywrightMetadataCollector } from './playwright.js';

/**
 * Factory function to create a metadata aggregator with all collectors registered
 *
 * @param playwrightConfig Optional Playwright FullConfig for enhanced metadata collection
 * @param playwrightSuite Optional Playwright Suite for skeleton building
 * @returns MetadataAggregator instance with all collectors registered
 */
export function createMetadataCollector(
  playwrightConfig?: PlaywrightFullConfig,
  playwrightSuite?: PlaywrightSuite
): MetadataAggregator {
  const aggregator = new MetadataAggregator();

  // Register all collectors
  aggregator.registerCollector(new GitMetadataCollector());
  aggregator.registerCollector(new CIMetadataCollector());
  aggregator.registerCollector(new SystemMetadataCollector());
  aggregator.registerCollector(
    new PlaywrightMetadataCollector({
      config: playwrightConfig,
      suite: playwrightSuite,
    })
  );

  return aggregator;
}
