/**
 * Artifact uploader for Azure Blob Storage
 * Uploads test artifacts (screenshots, videos, traces) using SAS tokens
 */

import { createReadStream, statSync } from 'fs';
import { basename, extname } from 'path';
import axios from 'axios';
import type { SASTokenResponse, UploadResult, AttachmentForUpload } from './types.js';
import { sleep } from '../utils/index.js';

export interface ArtifactUploaderOptions {
  /** Upload timeout per file in milliseconds */
  timeout?: number;
  /** Maximum retries per file */
  maxAttempts?: number;
  /** Debug mode for logging */
  debug?: boolean;
}

/**
 * Uploads artifacts to Azure Blob Storage using SAS tokens
 */
export class ArtifactUploader {
  private sasToken: SASTokenResponse;
  private options: Required<ArtifactUploaderOptions>;

  constructor(sasToken: SASTokenResponse, options: ArtifactUploaderOptions = {}) {
    this.sasToken = sasToken;
    this.options = {
      timeout: 60000,
      maxAttempts: 2,
      debug: false,
      ...options,
    };
  }

  /**
   * Upload a single file to Azure Blob Storage
   * @param attachment - Attachment with path and content type
   * @param testId - Test identifier for organizing uploads
   * @returns Upload result with Azure URL or error
   */
  async uploadFile(attachment: AttachmentForUpload, testId: string): Promise<UploadResult> {
    const startTime = Date.now();
    const fileName = basename(attachment.path);

    try {
      // Validate file exists and get size
      const stats = statSync(attachment.path);
      const fileSize = stats.size;

      // Check file size limit
      if (fileSize > this.sasToken.maxSize) {
        return {
          name: attachment.name,
          success: false,
          error: `File size ${fileSize} bytes exceeds maximum ${this.sasToken.maxSize} bytes`,
          fileSize,
          duration: Date.now() - startTime,
        };
      }

      // Check file type is allowed
      const extension = extname(fileName).slice(1).toLowerCase();
      const allowedTypes = this.sasToken.allowedFileTypes;
      if (allowedTypes.length > 0 && !allowedTypes.includes(extension)) {
        return {
          name: attachment.name,
          success: false,
          error: `File extension '.${extension}' not in allowed types: ${allowedTypes.join(', ')}`,
          fileSize,
          duration: Date.now() - startTime,
        };
      }

      // Build upload URL: baseUrl/pathPrefix/testId/fileName
      const uploadUrl = this.buildUploadUrl(testId, fileName);

      // Upload with retries
      await this.uploadWithRetry(attachment.path, uploadUrl, attachment.contentType);

      // Build public URL (without SAS token query params)
      const publicUrl = this.buildPublicUrl(testId, fileName);

      if (this.options.debug) {
        console.log(`📤 Uploaded: ${attachment.name} → ${publicUrl}`);
      }

      return {
        name: attachment.name,
        success: true,
        uploadUrl: publicUrl,
        fileSize,
        duration: Date.now() - startTime,
      };
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : String(error);

      if (this.options.debug) {
        console.warn(`⚠️  Upload failed: ${attachment.name} - ${errorMessage}`);
      }

      return {
        name: attachment.name,
        success: false,
        error: errorMessage,
        duration: Date.now() - startTime,
      };
    }
  }

  /**
   * Upload multiple attachments in parallel
   * @param attachments - Array of attachments to upload
   * @param testId - Test identifier for organizing uploads
   * @returns Array of upload results
   */
  async uploadAll(attachments: AttachmentForUpload[], testId: string): Promise<UploadResult[]> {
    if (attachments.length === 0) {
      return [];
    }

    // Filter to only attachments with valid paths
    const validAttachments = attachments.filter((a) => a.path);

    if (validAttachments.length === 0) {
      return [];
    }

    // Upload all in parallel using Promise.allSettled
    const results = await Promise.allSettled(validAttachments.map((attachment) => this.uploadFile(attachment, testId)));

    // Convert settled results to upload results
    return results.map((result, index) => {
      if (result.status === 'fulfilled') {
        return result.value;
      }
      // Promise rejection (shouldn't happen as uploadFile catches errors)
      return {
        name: validAttachments[index].name,
        success: false,
        error: result.reason?.message || 'Upload failed',
      };
    });
  }

  /**
   * Build the full upload URL with SAS token
   * Format: containerUrl/blobPath/uniqueId/testId/fileName?sasToken
   */
  private buildUploadUrl(testId: string, fileName: string): string {
    const { containerUrl, blobPath, uniqueId, sasToken } = this.sasToken;
    const path = `${blobPath}/${uniqueId}/${this.sanitizeTestId(testId)}/${fileName}`;
    return `${containerUrl}/${path}?${sasToken}`;
  }

  /**
   * Build public URL without SAS token (for storage in events)
   * Format: containerUrl/blobPath/uniqueId/testId/fileName
   */
  private buildPublicUrl(testId: string, fileName: string): string {
    const { containerUrl, blobPath, uniqueId } = this.sasToken;
    const path = `${blobPath}/${uniqueId}/${this.sanitizeTestId(testId)}/${fileName}`;
    return `${containerUrl}/${path}`;
  }

  /**
   * Sanitize test ID for use in URL path
   */
  private sanitizeTestId(testId: string): string {
    // Replace characters that are problematic in URLs
    return testId.replace(/[^a-zA-Z0-9-_]/g, '_');
  }

  /**
   * Upload file with retry logic
   */
  private async uploadWithRetry(filePath: string, uploadUrl: string, contentType: string): Promise<void> {
    let lastError: Error | null = null;

    for (let attempt = 0; attempt < this.options.maxAttempts; attempt++) {
      try {
        await this.doUpload(filePath, uploadUrl, contentType);
        return;
      } catch (error) {
        lastError = error instanceof Error ? error : new Error(String(error));

        if (attempt < this.options.maxAttempts - 1) {
          // Wait before retry with exponential backoff
          const delay = 1000 * Math.pow(2, attempt);
          await sleep(delay);
        }
      }
    }

    throw lastError || new Error('Upload failed after retries');
  }

  /**
   * Perform actual file upload to Azure
   */
  private async doUpload(filePath: string, uploadUrl: string, contentType: string): Promise<void> {
    const fileStream = createReadStream(filePath);
    const stats = statSync(filePath);

    await axios.put(uploadUrl, fileStream, {
      headers: {
        'Content-Type': contentType,
        'Content-Length': stats.size,
        'x-ms-blob-type': 'BlockBlob',
      },
      timeout: this.options.timeout,
      maxContentLength: Infinity,
      maxBodyLength: Infinity,
    });
  }

  /**
   * Check if SAS token is still valid
   */
  isTokenValid(): boolean {
    const expiresAt = new Date(this.sasToken.expiresAt).getTime();
    const now = Date.now();
    // Consider token invalid if it expires within 5 minutes
    return expiresAt > now + 5 * 60 * 1000;
  }

  /**
   * Get the unique ID for this upload session
   */
  getSessionId(): string {
    return this.sasToken.uniqueId;
  }
}
