/**
 * Incremental coverage merger using istanbul-lib-coverage.
 * Merges per-test coverage fragments as tests complete.
 * See docs/CODE_COVERAGE.md for design decisions and algorithms.
 */

import istanbulCoverage from 'istanbul-lib-coverage';
import picomatch from 'picomatch';
import { normalizePath } from '../utils/index.js';
import type { CoverageFragment, CoverageSummary, FileCoverage, CoverageMetric, IstanbulCoverageMap } from './types.js';

/**
 * Type adapter: our IstanbulCoverageMap → istanbul-lib-coverage CoverageMapData.
 * Both represent the same JSON shape; the double cast is isolated here.
 */
function toIstanbulMapData(map: IstanbulCoverageMap): istanbulCoverage.CoverageMapData {
  return map as unknown as istanbulCoverage.CoverageMapData;
}

/**
 * Type adapter: istanbul-lib-coverage CoverageMapData → our IstanbulCoverageMap.
 */
function fromIstanbulMapData(data: istanbulCoverage.CoverageMapData): IstanbulCoverageMap {
  return data as unknown as IstanbulCoverageMap;
}

/**
 * Options for filtering coverage files during merge.
 */
export interface CoverageMergerOptions {
  /** Glob patterns — only files whose path matches a pattern are included */
  include?: string[];
  /** Glob patterns — files whose path matches a pattern are excluded */
  exclude?: string[];
  /** Error callback for merge failures. Falls back to console.warn if not provided. */
  onError?: (message: string) => void;
}

/**
 * Incremental coverage merger.
 * Merges per-test Istanbul coverage fragments into a single coverage map.
 */
export class CoverageMerger {
  private coverageMap = istanbulCoverage.createCoverageMap({});
  private hasData = false;
  private includePatterns?: string[];
  private excludePatterns?: string[];
  private onError?: (message: string) => void;

  constructor(options?: CoverageMergerOptions) {
    this.includePatterns = options?.include;
    this.excludePatterns = options?.exclude;
    this.onError = options?.onError;
  }

  /**
   * Merge a coverage fragment from a completed test.
   * The fragment is merged directly and can be GC'd immediately.
   */
  addFragment(fragment: CoverageFragment): void {
    if (!fragment.istanbul) return;

    try {
      const filtered = this.filterCoverageMap(fragment.istanbul);
      this.coverageMap.merge(toIstanbulMapData(filtered));
      if (this.coverageMap.files().length > 0) {
        this.hasData = true;
      }
    } catch (error) {
      // Malformed coverage data — report and skip
      const msg = `[TestDino] Failed to merge coverage fragment: ${error instanceof Error ? error.message : String(error)}`;
      if (this.onError) {
        this.onError(msg);
      } else {
        console.warn(msg);
      }
    }
  }

  /**
   * Filter files from a coverage map based on include/exclude glob patterns.
   */
  private filterCoverageMap(coverageMap: IstanbulCoverageMap): IstanbulCoverageMap {
    const hasInclude = this.includePatterns && this.includePatterns.length > 0;
    const hasExclude = this.excludePatterns && this.excludePatterns.length > 0;

    if (!hasInclude && !hasExclude) return coverageMap;

    const isExcluded = hasExclude ? picomatch(this.excludePatterns!) : undefined;
    const isIncluded = hasInclude ? picomatch(this.includePatterns!) : undefined;

    const filtered: IstanbulCoverageMap = {};

    for (const [filePath, fileCoverage] of Object.entries(coverageMap)) {
      if (isExcluded && isExcluded(filePath)) {
        continue;
      }

      if (isIncluded && !isIncluded(filePath)) {
        continue;
      }

      filtered[filePath] = fileCoverage;
    }

    return filtered;
  }

  /**
   * Whether any coverage data has been collected.
   */
  get hasCoverage(): boolean {
    return this.hasData;
  }

  /**
   * Compute aggregate summary metrics from the merged coverage map.
   */
  computeSummary(): CoverageSummary {
    const globalSummary = this.coverageMap.getCoverageSummary();
    return {
      lines: extractMetric(globalSummary.lines),
      branches: extractMetric(globalSummary.branches),
      functions: extractMetric(globalSummary.functions),
      statements: extractMetric(globalSummary.statements),
    };
  }

  /**
   * Compute per-file coverage metrics.
   * Normalizes file paths to be relative to git root.
   */
  computeFileCoverage(gitRoot?: string): FileCoverage[] {
    const root = gitRoot || process.cwd();

    return this.coverageMap.files().map((filePath: string) => {
      const fileCoverage = this.coverageMap.fileCoverageFor(filePath);
      const fileSummary = fileCoverage.toSummary();

      // Normalize path to be relative to git root
      const normalizedPath = normalizePath(filePath, root);

      return {
        path: normalizedPath,
        lines: extractMetric(fileSummary.lines),
        branches: extractMetric(fileSummary.branches),
        functions: extractMetric(fileSummary.functions),
        statements: extractMetric(fileSummary.statements),
      };
    });
  }

  /**
   * Get the raw merged coverage map (for local report generation or compact extraction).
   */
  getRawCoverageMap(): istanbulCoverage.CoverageMap {
    return this.coverageMap;
  }

  /**
   * Get the merged coverage map as a plain JSON object.
   */
  toJSON(): IstanbulCoverageMap {
    return fromIstanbulMapData(this.coverageMap.toJSON());
  }
}

interface IstanbulSummaryMetric {
  total: number;
  covered: number;
  skipped: number;
  pct: number;
}

function extractMetric(metric: IstanbulSummaryMetric): CoverageMetric {
  return {
    total: metric.total,
    covered: metric.covered,
    pct: metric.pct,
  };
}
