/**
 * Base metadata collector implementation
 */

import type { MetadataCollector, MetadataCollectionResult } from './types.js';

/**
 * Abstract base class for metadata collectors
 * Provides common functionality and error handling patterns
 */
export abstract class BaseMetadataCollector<T = Record<string, unknown>> implements MetadataCollector<T> {
  protected name: string;

  constructor(name: string) {
    this.name = name;
  }

  /**
   * Get collector name
   */
  getName(): string {
    return this.name;
  }

  /**
   * Collect metadata with error handling and timing
   */
  async collect(): Promise<T> {
    try {
      const data = await this.collectMetadata();
      return data;
    } catch (error) {
      // Log error but don't throw - graceful degradation
      console.warn(
        `⚠️  TestDino: ${this.name} metadata collection failed:`,
        error instanceof Error ? error.message : String(error)
      );
      return this.getEmptyMetadata();
    }
  }

  /**
   * Collect metadata with result tracking
   */
  async collectWithResult(): Promise<MetadataCollectionResult<T>> {
    const startTime = Date.now();
    const collector = this.getName();

    try {
      const data = await this.collectMetadata();
      const duration = Date.now() - startTime;

      return {
        data,
        success: true,
        duration,
        collector,
      };
    } catch (error) {
      const duration = Date.now() - startTime;
      const errorMessage = error instanceof Error ? error.message : String(error);

      // Log error but return empty data for graceful degradation
      console.warn(`⚠️  TestDino: ${collector} metadata collection failed:`, errorMessage);

      return {
        data: this.getEmptyMetadata(),
        success: false,
        error: errorMessage,
        duration,
        collector,
      };
    }
  }

  /**
   * Abstract method to be implemented by concrete collectors
   */
  protected abstract collectMetadata(): Promise<T>;

  /**
   * Abstract method to provide empty metadata on errors
   */
  protected abstract getEmptyMetadata(): T;

  /**
   * Utility method to run command with timeout
   */
  protected async withTimeout<R>(promise: Promise<R>, timeoutMs: number, operation: string): Promise<R> {
    const timeoutPromise = new Promise<never>((_, reject) => {
      setTimeout(() => {
        reject(new Error(`${operation} timed out after ${timeoutMs}ms`));
      }, timeoutMs);
    });

    return Promise.race([promise, timeoutPromise]);
  }

  /**
   * Utility method to safely parse JSON
   */
  protected safeJsonParse<R>(jsonString: string, fallback: R): R {
    try {
      return JSON.parse(jsonString);
    } catch {
      return fallback;
    }
  }

  /**
   * Utility method to check if a value is non-empty string
   */
  protected isNonEmptyString(value: unknown): value is string {
    return typeof value === 'string' && value.trim().length > 0;
  }
}
