/**
 * CI metadata collector
 * Collects CI environment information, focusing on GitHub Actions
 */

import { type as osType, release as osRelease } from 'os';
import { BaseMetadataCollector } from './base.js';
import type { CIMetadata } from './types.js';

export interface CICollectorOptions {
  /**
   * Timeout for CI metadata collection in milliseconds
   * @default 3000
   */
  timeout?: number;
}

/**
 * Collects CI environment metadata
 */
export class CIMetadataCollector extends BaseMetadataCollector<CIMetadata> {
  constructor(_options: CICollectorOptions = {}) {
    super('ci');
  }

  /**
   * Collect CI metadata
   */
  protected async collectMetadata(): Promise<CIMetadata> {
    const provider = this.detectCIProvider();

    if (!provider) {
      return {
        provider: 'local',
        environment: this.collectEnvironment(),
      };
    }

    if (provider === 'github-actions') {
      return this.collectGitHubActionsMetadata();
    }

    // Fallback for unknown CI providers
    return {
      provider,
      environment: this.collectEnvironment(),
    };
  }

  /**
   * Get empty metadata
   */
  protected getEmptyMetadata(): CIMetadata {
    return {};
  }

  /**
   * Detect CI provider from environment variables
   */
  private detectCIProvider(): string | undefined {
    const { env } = process;

    // GitHub Actions detection
    if (env.GITHUB_ACTIONS === 'true') {
      return 'github-actions';
    }

    // Could add other CI providers here in the future
    // if (env.GITLAB_CI) return 'gitlab';
    // if (env.CIRCLECI) return 'circleci';

    return undefined;
  }

  /**
   * Collect GitHub Actions specific metadata
   */
  private collectGitHubActionsMetadata(): CIMetadata {
    const { env } = process;

    return {
      provider: 'github-actions',
      pipeline: {
        id: env.GITHUB_RUN_ID,
        name: env.GITHUB_WORKFLOW,
        url: this.buildPipelineUrl(),
      },
      build: {
        number: env.GITHUB_RUN_NUMBER,
        trigger: env.GITHUB_EVENT_NAME,
      },
      environment: this.collectEnvironment(),
    };
  }

  /**
   * Build the pipeline URL from GitHub Actions environment variables
   */
  private buildPipelineUrl(): string | undefined {
    const { env } = process;
    const serverUrl = env.GITHUB_SERVER_URL;
    const repository = env.GITHUB_REPOSITORY;
    const runId = env.GITHUB_RUN_ID;

    if (serverUrl && repository && runId) {
      return `${serverUrl}/${repository}/actions/runs/${runId}`;
    }

    return undefined;
  }

  /**
   * Collect runner environment information
   */
  private collectEnvironment(): CIMetadata['environment'] {
    try {
      return {
        name: osType(),
        type: process.platform,
        os: `${osType()} ${osRelease()}`,
        node: process.version,
      };
    } catch {
      return {};
    }
  }
}
