/**
 * Playwright metadata collector
 * Collects Playwright configuration and version information
 */

import { readFile } from 'fs/promises';
import { BaseMetadataCollector } from './base.js';
import type {
  PlaywrightMetadata,
  ProjectConfig,
  ProjectUseOptions,
  RunSkeleton,
  SkeletonSuite,
  SkeletonTest,
} from './types.js';

/**
 * Playwright FullProject interface (per-project config)
 * @see docs/PLAYWRIGHT-TYPES-REFERENCE.md
 */
interface PlaywrightFullProject {
  name?: string;
  testDir?: string;
  timeout?: number;
  retries?: number;
  repeatEach?: number;
  dependencies?: string[];
  grep?: RegExp | RegExp[];
  use?: {
    browserName?: 'chromium' | 'firefox' | 'webkit';
    defaultBrowserType?: 'chromium' | 'firefox' | 'webkit'; // From device presets
    channel?: string;
    headless?: boolean;
    viewport?: { width: number; height: number } | null;
    baseURL?: string;
    trace?: 'off' | 'on' | 'retain-on-failure' | 'on-first-retry' | { mode: string };
    screenshot?: 'off' | 'on' | 'only-on-failure' | { mode: string };
    video?: 'off' | 'on' | 'retain-on-failure' | 'on-first-retry' | { mode: string };
    isMobile?: boolean;
    locale?: string;
    [key: string]: unknown;
  };
}

/**
 * Playwright FullConfig interface (global config)
 * Note: testDir, timeout, retries are on FullProject, not FullConfig
 * @see docs/PLAYWRIGHT-TYPES-REFERENCE.md
 */
interface PlaywrightFullConfig {
  fullyParallel?: boolean;
  workers?: number;
  shard?: {
    current: number;
    total: number;
  } | null;
  projects?: PlaywrightFullProject[];
  version?: string;
  configFile?: string;
  forbidOnly?: boolean;
  globalTimeout?: number;
  grep?: RegExp | RegExp[];
  maxFailures?: number;
  metadata?: Record<string, unknown>;
  reportSlowTests?: {
    max: number;
    threshold: number;
  } | null;
  rootDir?: string;
  tags?: string[];
  webServer?: Record<string, unknown> | null;
}

/**
 * Playwright Suite interface (minimal)
 */
interface PlaywrightSuite {
  title: string;
  type: 'root' | 'project' | 'file' | 'describe';
  location?: {
    file: string;
    line: number;
    column: number;
  };
  suites: PlaywrightSuite[];
  tests: PlaywrightTestCase[];
  allTests(): PlaywrightTestCase[];
}

/**
 * Playwright TestCase interface (minimal)
 */
interface PlaywrightTestCase {
  id: string;
  title: string;
  location: {
    file: string;
    line: number;
    column: number;
  };
  tags: string[];
  expectedStatus: 'passed' | 'failed' | 'timedOut' | 'skipped' | 'interrupted';
  annotations: Array<{
    type: string;
    description?: string;
  }>;
}

export interface PlaywrightCollectorOptions {
  /**
   * Timeout for Playwright metadata collection in milliseconds
   * @default 3000
   */
  timeout?: number;

  /**
   * Playwright FullConfig object (when available from reporter context)
   */
  config?: PlaywrightFullConfig;

  /**
   * Playwright Suite object (when available from reporter context)
   */
  suite?: PlaywrightSuite;

  /**
   * Custom path to @playwright/test package.json for testing
   */
  packageJsonPath?: string;
}

/**
 * Collects Playwright metadata including version and configuration
 */
export class PlaywrightMetadataCollector extends BaseMetadataCollector<PlaywrightMetadata> {
  private options: Required<Omit<PlaywrightCollectorOptions, 'config' | 'suite' | 'packageJsonPath'>> &
    Pick<PlaywrightCollectorOptions, 'config' | 'suite' | 'packageJsonPath'>;

  constructor(options: PlaywrightCollectorOptions = {}) {
    super('playwright');
    this.options = {
      timeout: options.timeout || 3000,
      config: options.config,
      suite: options.suite,
      packageJsonPath: options.packageJsonPath,
    };
  }

  /**
   * Collect Playwright metadata
   */
  protected async collectMetadata(): Promise<PlaywrightMetadata> {
    const metadata: PlaywrightMetadata = {};

    // Collect version (always attempt this)
    const version = await this.getPlaywrightVersion();
    if (version) {
      metadata.version = version;
    }

    // Collect config metadata if FullConfig is available
    if (this.options.config) {
      const configMetadata = this.extractConfigMetadata(this.options.config);
      Object.assign(metadata, configMetadata);
    }

    return metadata;
  }

  /**
   * Build skeleton from Suite and include it in CompleteMetadata
   */
  buildSkeletonMetadata(suite: PlaywrightSuite): { skeleton: RunSkeleton } {
    const skeleton = this.buildSkeleton(suite);
    return { skeleton };
  }

  /**
   * Get empty metadata
   */
  protected getEmptyMetadata(): PlaywrightMetadata {
    return {};
  }

  /**
   * Get Playwright version from @playwright/test package.json
   */
  private async getPlaywrightVersion(): Promise<string | undefined> {
    try {
      const packageJsonPath = this.options.packageJsonPath || this.resolvePlaywrightPackageJson();

      if (!packageJsonPath) {
        return undefined;
      }

      const packageJsonContent = await this.withTimeout(
        readFile(packageJsonPath, 'utf-8'),
        this.options.timeout,
        'Playwright package.json read'
      );

      const packageJson = this.safeJsonParse<{ version?: string }>(packageJsonContent, {});

      return this.isNonEmptyString(packageJson.version) ? packageJson.version : undefined;
    } catch (error) {
      // Log error but don't fail the entire collection
      console.warn(
        '⚠️  TestDino: Failed to read Playwright version:',
        error instanceof Error ? error.message : String(error)
      );
      return undefined;
    }
  }

  /**
   * Resolve @playwright/test package.json path
   */
  private resolvePlaywrightPackageJson(): string | undefined {
    try {
      // Try to resolve @playwright/test package.json
      return require.resolve('@playwright/test/package.json');
    } catch {
      // @playwright/test not found
      return undefined;
    }
  }

  /**
   * Extract metadata from Playwright FullConfig
   */
  private extractConfigMetadata(config: PlaywrightFullConfig): Partial<PlaywrightMetadata> {
    const metadata: Partial<PlaywrightMetadata> = {};

    // Config file path
    if (this.isNonEmptyString(config.configFile)) {
      metadata.configFile = config.configFile;
    }

    // Forbid only
    if (typeof config.forbidOnly === 'boolean') {
      metadata.forbidOnly = config.forbidOnly;
    }

    // Fully parallel mode
    if (typeof config.fullyParallel === 'boolean') {
      metadata.fullyParallel = config.fullyParallel;
      metadata.parallel = config.fullyParallel; // Keep for backward compatibility
    }

    // Global timeout
    if (typeof config.globalTimeout === 'number') {
      metadata.globalTimeout = config.globalTimeout;
    }

    // Grep pattern(s)
    if (config.grep) {
      const patterns = Array.isArray(config.grep) ? config.grep : [config.grep];
      metadata.grep = patterns.map((p) => p.source);
    }

    // Max failures
    if (typeof config.maxFailures === 'number') {
      metadata.maxFailures = config.maxFailures;
    }

    // Custom metadata
    if (config.metadata && typeof config.metadata === 'object') {
      metadata.metadata = config.metadata;
    }

    // Workers
    if (typeof config.workers === 'number') {
      metadata.workers = config.workers;
    }

    // Projects (full configuration from FullProject)
    if (Array.isArray(config.projects) && config.projects.length > 0) {
      const projectConfigs = config.projects
        .filter((project) => this.isNonEmptyString(project.name))
        .map((project) => this.extractProjectConfig(project));

      if (projectConfigs.length > 0) {
        metadata.projects = projectConfigs;

        // Extract unique browsers from all projects
        const browsers = this.extractBrowsersFromProjects(config.projects);
        if (browsers.length > 0) {
          metadata.browsers = browsers;
        }
      }
    }

    // Report slow tests
    if (config.reportSlowTests && typeof config.reportSlowTests === 'object') {
      metadata.reportSlowTests = {
        max: config.reportSlowTests.max,
        threshold: config.reportSlowTests.threshold,
      };
    }

    // Root directory
    if (this.isNonEmptyString(config.rootDir)) {
      metadata.rootDir = config.rootDir;
    }

    // Shard information
    if (config.shard && typeof config.shard.current === 'number' && typeof config.shard.total === 'number') {
      metadata.shard = {
        current: config.shard.current,
        total: config.shard.total,
      };
    }

    // Tags
    if (Array.isArray(config.tags) && config.tags.length > 0) {
      metadata.tags = config.tags;
    }

    // Web server
    if (config.webServer && typeof config.webServer === 'object') {
      metadata.webServer = config.webServer;
    }

    return metadata;
  }

  /**
   * Extract project configuration from FullProject
   */
  private extractProjectConfig(project: PlaywrightFullProject): ProjectConfig {
    const config: ProjectConfig = {
      name: project.name || '',
    };

    // Project-level settings (these exist on FullProject, not FullConfig)
    if (this.isNonEmptyString(project.testDir)) {
      config.testDir = project.testDir;
    }

    if (typeof project.timeout === 'number') {
      config.timeout = project.timeout;
    }

    if (typeof project.retries === 'number') {
      config.retries = project.retries;
    }

    if (typeof project.repeatEach === 'number' && project.repeatEach > 1) {
      config.repeatEach = project.repeatEach;
    }

    // Dependencies (projects that must run first)
    if (Array.isArray(project.dependencies) && project.dependencies.length > 0) {
      config.dependencies = project.dependencies;
    }

    // Project-specific grep patterns
    if (project.grep) {
      const patterns = Array.isArray(project.grep) ? project.grep : [project.grep];
      const grepStrings = patterns.map((p) => p.source);
      if (grepStrings.length > 0) {
        config.grep = grepStrings;
      }
    }

    // Extract use options (browser, viewport, etc.)
    if (project.use) {
      const useOptions = this.extractUseOptions(project.use);
      if (Object.keys(useOptions).length > 0) {
        config.use = useOptions;
      }
    }

    return config;
  }

  /**
   * Extract use options from project.use
   */
  private extractUseOptions(use: PlaywrightFullProject['use']): ProjectUseOptions {
    const options: ProjectUseOptions = {};

    if (!use) return options;

    // Extract channel first (needed for browser inference)
    if (this.isNonEmptyString(use.channel)) {
      options.channel = use.channel;
    }

    // Determine browserName - explicit or inferred from channel
    const browserName = this.resolveBrowserName(use.browserName, use.defaultBrowserType, use.channel);
    if (browserName) {
      options.browserName = browserName;
    }

    if (typeof use.headless === 'boolean') {
      options.headless = use.headless;
    }

    if (use.viewport && typeof use.viewport === 'object') {
      options.viewport = {
        width: use.viewport.width,
        height: use.viewport.height,
      };
    } else if (use.viewport === null) {
      options.viewport = null;
    }

    if (this.isNonEmptyString(use.baseURL)) {
      options.baseURL = use.baseURL;
    }

    // Artifact capture settings
    const trace = this.normalizeArtifactMode(use.trace);
    if (trace) {
      options.trace = trace;
    }

    const screenshot = this.normalizeArtifactMode(use.screenshot);
    if (screenshot) {
      options.screenshot = screenshot;
    }

    const video = this.normalizeArtifactMode(use.video);
    if (video) {
      options.video = video;
    }

    // Device emulation
    if (typeof use.isMobile === 'boolean') {
      options.isMobile = use.isMobile;
    }

    // Locale
    if (this.isNonEmptyString(use.locale)) {
      options.locale = use.locale;
    }

    return options;
  }

  /**
   * Normalize artifact mode (trace/screenshot/video can be string or { mode: string })
   */
  private normalizeArtifactMode(value: unknown): string | undefined {
    if (!value) return undefined;
    if (typeof value === 'string' && value !== 'off') {
      return value;
    }
    if (typeof value === 'object' && value !== null && 'mode' in value) {
      const mode = (value as { mode: string }).mode;
      if (mode && mode !== 'off') {
        return mode;
      }
    }
    return undefined;
  }

  /**
   * Resolve browserName from explicit value, defaultBrowserType (device presets), or channel
   * Priority: browserName > defaultBrowserType > channel inference
   */
  private resolveBrowserName(
    browserName: string | undefined,
    defaultBrowserType: string | undefined,
    channel: string | undefined
  ): 'chromium' | 'firefox' | 'webkit' | undefined {
    const validBrowsers = ['chromium', 'firefox', 'webkit'];

    // 1. Use explicit browserName if valid
    if (browserName && validBrowsers.includes(browserName)) {
      return browserName as 'chromium' | 'firefox' | 'webkit';
    }

    // 2. Use defaultBrowserType from device presets (e.g., devices['Desktop Chrome'])
    if (defaultBrowserType && validBrowsers.includes(defaultBrowserType)) {
      return defaultBrowserType as 'chromium' | 'firefox' | 'webkit';
    }

    // 3. Infer from channel
    if (channel) {
      // Chrome-based channels use chromium engine
      if (
        [
          'chrome',
          'chrome-beta',
          'chrome-dev',
          'chrome-canary',
          'msedge',
          'msedge-beta',
          'msedge-dev',
          'msedge-canary',
        ].includes(channel)
      ) {
        return 'chromium';
      }
    }

    return undefined;
  }

  /**
   * Extract unique browsers from all projects
   */
  private extractBrowsersFromProjects(projects: PlaywrightFullProject[]): string[] {
    const browsers = new Set<string>();

    for (const project of projects) {
      const browserName = this.resolveBrowserName(
        project.use?.browserName,
        project.use?.defaultBrowserType,
        project.use?.channel
      );
      if (browserName) {
        browsers.add(browserName);
      }
    }

    return Array.from(browsers);
  }

  /**
   * Build skeleton from Suite
   */
  buildSkeleton(suite: PlaywrightSuite): RunSkeleton {
    const totalTests = suite.allTests().length;
    const suites = this.buildSuiteTree(suite);

    return {
      totalTests,
      suites,
    };
  }

  /**
   * Recursively build suite tree
   */
  private buildSuiteTree(suite: PlaywrightSuite): SkeletonSuite[] {
    const suites: SkeletonSuite[] = [];

    // Process child suites
    for (const childSuite of suite.suites) {
      const skeletonSuite: SkeletonSuite = {
        title: childSuite.title,
        type: childSuite.type === 'file' ? 'file' : 'describe',
        tests: childSuite.tests.map((test) => this.buildSkeletonTest(test)),
      };

      // Add file for file-type suites
      if (childSuite.type === 'file' && childSuite.location) {
        skeletonSuite.file = childSuite.location.file;
      }

      // Add location if available
      if (childSuite.location) {
        skeletonSuite.location = {
          file: childSuite.location.file,
          line: childSuite.location.line,
          column: childSuite.location.column,
        };
      }

      // Recursively build nested suites
      if (childSuite.suites.length > 0) {
        skeletonSuite.suites = this.buildSuiteTree(childSuite);
      }

      suites.push(skeletonSuite);
    }

    return suites;
  }

  /**
   * Build skeleton test from TestCase
   */
  private buildSkeletonTest(test: PlaywrightTestCase): SkeletonTest {
    const skeletonTest: SkeletonTest = {
      testId: test.id,
      title: test.title,
      location: {
        file: test.location.file,
        line: test.location.line,
        column: test.location.column,
      },
    };

    // Add tags if present
    if (test.tags && test.tags.length > 0) {
      skeletonTest.tags = test.tags;
    }

    // Add expected status
    if (test.expectedStatus) {
      skeletonTest.expectedStatus = test.expectedStatus;
    }

    // Add annotations if present
    if (test.annotations && test.annotations.length > 0) {
      skeletonTest.annotations = test.annotations.map((ann) => ({
        type: ann.type,
        description: ann.description,
      }));
    }

    return skeletonTest;
  }
}
