/**
 * System metadata collector
 * Collects system information using Node.js built-in modules
 */

import { platform, release, cpus, totalmem, hostname } from 'os';
import { version } from 'process';
import { BaseMetadataCollector } from './base.js';
import type { SystemMetadata } from './types.js';

// eslint-disable-next-line @typescript-eslint/no-empty-object-type
export interface SystemCollectorOptions {
  // Reserved for future options
}

/**
 * Collects system metadata using Node.js built-in modules
 */
export class SystemMetadataCollector extends BaseMetadataCollector<SystemMetadata> {
  constructor(_options: SystemCollectorOptions = {}) {
    super('system');
    // System metadata collection is synchronous and doesn't need configuration
  }

  /**
   * Collect system metadata
   */
  protected async collectMetadata(): Promise<SystemMetadata> {
    // System metadata collection is synchronous and fast
    // but we wrap it in a promise for consistency with other collectors
    return new Promise((resolve) => {
      const metadata: SystemMetadata = {
        os: this.getOperatingSystem(),
        cpu: this.getCpuInfo(),
        memory: this.getMemoryInfo(),
        nodeVersion: this.getNodeVersion(),
        platform: this.getPlatform(),
        hostname: this.getHostname(),
      };

      resolve(metadata);
    });
  }

  /**
   * Get empty metadata
   */
  protected getEmptyMetadata(): SystemMetadata {
    return {};
  }

  /**
   * Get operating system information
   * Format: "platform release" (e.g., "darwin 23.1.0", "linux 5.4.0")
   */
  private getOperatingSystem(): string {
    let platformName = 'unknown';
    let releaseVersion = 'unknown';

    try {
      platformName = platform();
    } catch {
      // Keep default 'unknown'
    }

    try {
      releaseVersion = release();
    } catch {
      // Keep default 'unknown'
    }

    return `${platformName} ${releaseVersion}`;
  }

  /**
   * Get CPU information
   * Format: "model (X cores)" (e.g., "Intel(R) Core(TM) i7-9750H CPU @ 2.60GHz (12 cores)")
   */
  private getCpuInfo(): string {
    try {
      const cpuList = cpus();
      if (cpuList.length === 0) {
        return 'unknown';
      }

      const model = cpuList[0].model.trim();
      const coreCount = cpuList.length;

      return `${model} (${coreCount} cores)`;
    } catch {
      return 'unknown';
    }
  }

  /**
   * Get memory information
   * Format: "X.X GB" (e.g., "16.0 GB", "8.5 GB")
   */
  private getMemoryInfo(): string {
    try {
      const totalBytes = totalmem();
      const totalGB = totalBytes / (1024 * 1024 * 1024);

      // Round to 1 decimal place
      return `${totalGB.toFixed(1)} GB`;
    } catch {
      return 'unknown';
    }
  }

  /**
   * Get Node.js version
   * Returns process.version (e.g., "v18.17.0")
   */
  private getNodeVersion(): string {
    try {
      return version;
    } catch {
      return 'unknown';
    }
  }

  /**
   * Get platform identifier
   * Returns os.platform() (e.g., "darwin", "linux", "win32")
   */
  private getPlatform(): string {
    try {
      return platform();
    } catch {
      return 'unknown';
    }
  }

  /**
   * Get hostname
   * Returns os.hostname() (e.g., "MacBook-Pro.local")
   */
  private getHostname(): string {
    try {
      return hostname();
    } catch {
      return 'unknown';
    }
  }
}
