/**
 * Coverage fixtures for automatic Istanbul coverage collection.
 *
 * The fixture runs automatically (auto: true) for every test:
 * 1. Test executes normally
 * 2. After test: extracts window.__coverage__ from the page
 * 3. Attaches coverage JSON to testInfo for the reporter to pick up
 *
 * Gracefully no-ops when the app is not instrumented (window.__coverage__ absent).
 */

import { test as base, expect, type Page, type TestInfo } from '@playwright/test';
import type { IstanbulCoverageMap, CoverageFragment } from './types.js';

// Timeout for extracting Istanbul coverage from the page (30 seconds)
const COVERAGE_EXTRACT_TIMEOUT_MS = 30_000;

type CoverageFixtures = {
  _testdinoCoverage: void;
};

/**
 * Extract Istanbul coverage from a Playwright Page.
 * Returns null if window.__coverage__ does not exist or if extraction times out.
 */
export async function extractCoverageFromPage(
  page: Page,
  timeoutMs: number = COVERAGE_EXTRACT_TIMEOUT_MS
): Promise<IstanbulCoverageMap | null> {
  return Promise.race([
    page.evaluate(() => (globalThis as unknown as { __coverage__?: IstanbulCoverageMap }).__coverage__ ?? null),
    new Promise<null>((resolve) => setTimeout(() => resolve(null), timeoutMs)),
  ]).catch(() => null);
}

/**
 * Attach an Istanbul coverage map to a TestInfo as a JSON attachment.
 * The reporter picks up the attachment by name ('testdino-coverage').
 */
export async function attachCoverageToTestInfo(testInfo: TestInfo, coverage: IstanbulCoverageMap): Promise<void> {
  const fragment: CoverageFragment = {
    istanbul: coverage,
  };

  await testInfo.attach('testdino-coverage', {
    body: JSON.stringify(fragment),
    contentType: 'application/json',
  });
}

export const coverageFixtures = {
  _testdinoCoverage: [
    async ({ page }: { page: Page }, use: () => Promise<void>, testInfo: TestInfo) => {
      // Test executes here
      await use();

      // Extract Istanbul coverage (any browser, if app is instrumented).
      const istanbulCoverage = await extractCoverageFromPage(page);

      // Attach coverage data to test result for the reporter to pick up
      if (istanbulCoverage) {
        await attachCoverageToTestInfo(testInfo, istanbulCoverage);
      }
    },
    { auto: true },
  ],
};

/**
 * Pre-extended test with coverage fixtures for direct import.
 *
 * Usage:
 * ```typescript
 * import { test, expect } from '@testdino/playwright';
 *
 * test('my test', async ({ page }) => {
 *   // coverage collected automatically
 * });
 * ```
 */
export const test = base.extend<CoverageFixtures>(
  coverageFixtures as Parameters<typeof base.extend<CoverageFixtures>>[0]
);
export { expect };
