/**
 * Kafka event producer for streaming test events to Redpanda/Kafka
 * Uses KafkaJS for broad Kafka protocol compatibility (v0-v8 Metadata API)
 */

import { Kafka, type Producer, type RecordMetadata, type SASLOptions } from 'kafkajs';
import type { TestEvent } from '../types/index.js';

export interface KafkaProducerOptions {
  /** Kafka/Redpanda broker addresses (e.g. ['localhost:19092']) */
  brokers: string[];
  /** Topic to produce events to */
  topic: string;
  /** Client identifier */
  clientId?: string;
  /** SASL authentication (for Redpanda Cloud) */
  sasl?: SASLOptions;
  /** Enable TLS (for Redpanda Cloud) */
  ssl?: boolean;
  /** Connection timeout in milliseconds */
  connectionTimeout?: number;
  /** Enable debug logging */
  debug?: boolean;
}

export interface KafkaSendResult {
  topicName: string;
  partition: number;
  offset: string;
}

export class KafkaEventProducer {
  private kafka: Kafka;
  private producer: Producer | null = null;
  private topic: string;
  private options: KafkaProducerOptions;
  private connected = false;
  private connectPromise: Promise<void> | null = null;

  constructor(options: KafkaProducerOptions) {
    this.options = options;
    this.topic = options.topic;

    this.kafka = new Kafka({
      clientId: options.clientId ?? 'testdino-reporter',
      brokers: options.brokers,
      connectionTimeout: options.connectionTimeout ?? 10_000,
      ...(options.sasl && { sasl: options.sasl }),
      ...(options.ssl !== undefined && { ssl: options.ssl }),
    });
  }

  /**
   * Connect to the Kafka/Redpanda cluster.
   * Must be called before send().
   */
  async connect(): Promise<void> {
    if (this.connected) return;

    // Serialize concurrent connect() calls — second caller waits for first
    if (this.connectPromise) {
      return this.connectPromise;
    }

    this.connectPromise = this.doConnect();
    try {
      await this.connectPromise;
    } finally {
      this.connectPromise = null;
    }
  }

  private async doConnect(): Promise<void> {
    this.producer = this.kafka.producer();
    await this.producer.connect();
    this.connected = true;

    if (this.options.debug) {
      console.log(`TestDino: ℹ️ Kafka producer connected to ${this.options.brokers.join(', ')}`);
    }
  }

  /**
   * Send a single event and wait for broker acknowledgement (acks=1).
   * Uses runId as partition key to guarantee ordering within a run.
   */
  async send(event: TestEvent): Promise<RecordMetadata[]> {
    if (!this.producer) {
      throw new Error('KafkaEventProducer not connected — call connect() first');
    }

    const result = await this.producer.send({
      topic: this.topic,
      acks: 1,
      messages: [
        {
          key: event.runId,
          value: JSON.stringify(event),
        },
      ],
    });

    if (this.options.debug) {
      const meta = result[0];
      console.log(
        `TestDino: ✅ Kafka delivered type=${event.type} seq=${event.sequence} ` +
          `partition=${meta?.partition ?? '?'} offset=${meta?.offset ?? '?'}`
      );
    }

    return result;
  }

  /**
   * Send a batch of events in a single produce request.
   * All events use the same partition key (runId) for ordering.
   */
  async sendBatch(events: TestEvent[]): Promise<RecordMetadata[]> {
    if (!this.producer) {
      throw new Error('KafkaEventProducer not connected — call connect() first');
    }

    if (events.length === 0) {
      return [];
    }

    const result = await this.producer.send({
      topic: this.topic,
      acks: 1,
      messages: events.map((event) => ({
        key: event.runId,
        value: JSON.stringify(event),
      })),
    });

    if (this.options.debug) {
      console.log(
        `TestDino: ✅ Kafka batch delivered ${events.length} events ` +
          `(seq ${events[0].sequence}–${events[events.length - 1].sequence})`
      );
    }

    return result;
  }

  /**
   * Gracefully close the producer connection.
   */
  async close(): Promise<void> {
    if (this.producer) {
      const producer = this.producer;
      this.producer = null;
      this.connected = false;

      try {
        await producer.disconnect();
      } catch (error) {
        // Ignore disconnect errors — connection may already be dead (EPIPE)
      }

      if (this.options.debug) {
        console.log('TestDino: ℹ️ Kafka producer closed');
      }
    }
  }

  /** Whether the producer is connected */
  get isConnected(): boolean {
    return this.connected;
  }
}
