/**
 * Compact count extractor for cross-shard coverage merging.
 * Extracts minimal hit count data from merged coverage maps.
 * See docs/CODE_COVERAGE.md for design decisions and algorithms.
 */

import { createHash } from 'crypto';
import { normalizePath } from '../utils/index.js';
import type { CompactCoverageData, CompactFileCounts, IstanbulFileCoverage } from './types.js';

/**
 * Extract compact hit counts from a merged coverage map JSON.
 *
 * @param coverageMapJSON - Raw coverage map data from CoverageMerger.toJSON()
 * @param gitRoot - Git repository root for path normalization (optional)
 * @returns Compact coverage data suitable for cross-shard upload
 */
export function extractCompactCounts(
  coverageMapJSON: Record<string, IstanbulFileCoverage>,
  gitRoot?: string
): CompactCoverageData {
  const files: Record<string, CompactFileCounts> = {};
  let fileCount = 0;

  for (const [filePath, fileCoverage] of Object.entries(coverageMapJSON)) {
    const normalizedPath = normalizePath(filePath, gitRoot);

    files[normalizedPath] = {
      s: fileCoverage.s,
      f: fileCoverage.f,
      b: fileCoverage.b,
      totals: {
        s: Object.keys(fileCoverage.statementMap || {}).length,
        f: Object.keys(fileCoverage.fnMap || {}).length,
        b: countBranchPaths(fileCoverage.branchMap || {}),
      },
      shapeHash: computeShapeHash(fileCoverage),
    };
    fileCount++;
  }

  return { files, fileCount };
}

/**
 * Count total branch paths across all branches in a file.
 * Each branch (if/else, ternary, switch) can have multiple paths.
 */
function countBranchPaths(branchMap: IstanbulFileCoverage['branchMap']): number {
  let total = 0;
  for (const branch of Object.values(branchMap)) {
    total += (branch.locations || []).length;
  }
  return total;
}

/**
 * Compute a shape hash from the structural maps of a file.
 * Used to detect build mismatches across shards — if two shards produce
 * different shape hashes for the same file, the builds were different.
 *
 * The hash encodes the count of statements, functions, and branch paths,
 * plus the per-branch path counts for granularity.
 */
function computeShapeHash(fileCoverage: IstanbulFileCoverage): string {
  const branchMap = fileCoverage.branchMap || {};
  const shape = {
    s: Object.keys(fileCoverage.statementMap || {}).length,
    f: Object.keys(fileCoverage.fnMap || {}).length,
    b: countBranchPaths(branchMap),
    bp: Object.values(branchMap).map((b) => (b.locations || []).length),
  };
  return createHash('sha256').update(JSON.stringify(shape)).digest('hex').slice(0, 12);
}
