/**
 * Server error classes for quota and infrastructure errors
 * These are received from the TestDino server and handled gracefully in the reporter
 * Follows the same Error class pattern as cli/errors.ts
 */

/**
 * Base class for all TestDino server errors
 * Extends Error to work with standard error handling
 */
export class TestDinoServerError extends Error {
  public readonly code: string;

  constructor(code: string, message: string) {
    super(message);
    this.name = 'TestDinoServerError';
    this.code = code;
    Error.captureStackTrace(this, this.constructor);
  }
}

/**
 * Quota exhausted error (session creation)
 * HTTP 402 response when organization pool is exhausted
 */
export class QuotaExhaustedError extends TestDinoServerError {
  public readonly details: {
    planName: string;
    totalLimit: number;
    used: number;
    resetDate?: string;
  };

  constructor(
    message: string,
    details: {
      planName: string;
      totalLimit: number;
      used: number;
      resetDate?: string;
    }
  ) {
    super('QUOTA_EXHAUSTED', message);
    this.name = 'QuotaExhaustedError';
    this.details = details;
  }
}

/**
 * Quota exceeded error (run:begin)
 * WebSocket NACK when test count exceeds available quota
 */
export class QuotaExceededError extends TestDinoServerError {
  public readonly details: {
    planName: string;
    totalTests: number;
    remaining: number;
    used: number;
    total: number;
    resetDate?: string;
    canPartialSubmit: boolean;
    allowedCount: number;
  };

  constructor(
    message: string,
    details: {
      planName: string;
      totalTests: number;
      remaining: number;
      used: number;
      total: number;
      resetDate?: string;
      canPartialSubmit: boolean;
      allowedCount: number;
    }
  ) {
    super('QUOTA_EXCEEDED', message);
    this.name = 'QuotaExceededError';
    this.details = details;
  }
}

/**
 * Union type for all server error classes
 */
export type ServerError = QuotaExhaustedError | QuotaExceededError;

/**
 * Type guard to check if error is a server error instance
 * @param error - Unknown error value to check
 * @returns true if error is an instance of TestDinoServerError
 */
export function isServerError(error: unknown): error is ServerError {
  return error instanceof TestDinoServerError;
}

/**
 * Type guard to check if error is a quota-related error
 * @param error - Unknown error value to check
 * @returns true if error is QuotaExhaustedError or QuotaExceededError
 */
export function isQuotaError(error: unknown): error is QuotaExhaustedError | QuotaExceededError {
  return error instanceof QuotaExhaustedError || error instanceof QuotaExceededError;
}
