/**
 * Event buffer for batching and managing event transmission
 */

import type { TestEvent } from '../types/index.js';

export interface EventBufferOptions {
  maxSize?: number;
  onFlush?: (events: TestEvent[]) => Promise<void>;
}

export class EventBuffer {
  private events: TestEvent[] = [];
  private maxSize: number;
  private onFlush: (events: TestEvent[]) => Promise<void>;
  private flushPromise: Promise<void> | null = null;

  constructor(options: EventBufferOptions) {
    this.maxSize = options.maxSize || 10;
    this.onFlush = options.onFlush || (async () => {});
  }

  /**
   * Add event to buffer
   * Automatically flushes if buffer reaches max size
   */
  async add(event: TestEvent): Promise<void> {
    this.events.push(event);

    if (this.events.length >= this.maxSize) {
      await this.flush();
    }
  }

  /**
   * Flush all buffered events
   * If a flush is already in progress, waits for it to complete then flushes any new events
   */
  async flush(): Promise<void> {
    // If a flush is in progress, wait for it to complete
    if (this.flushPromise) {
      await this.flushPromise;
      // After waiting, check if there are more events to flush (added during wait)
      // Recursively call flush to handle them
      if (this.events.length > 0) {
        return this.flush();
      }
      return;
    }

    // Nothing to flush
    if (this.events.length === 0) {
      return;
    }

    // Start the flush operation and track it
    this.flushPromise = this.doFlush();

    try {
      await this.flushPromise;
    } finally {
      this.flushPromise = null;
    }
  }

  /**
   * Internal flush implementation
   */
  private async doFlush(): Promise<void> {
    const eventsToFlush = [...this.events];
    this.events = [];
    try {
      await this.onFlush(eventsToFlush);
    } catch (error) {
      // Restore failed events to front of buffer for retry on next flush
      this.events = [...eventsToFlush, ...this.events];
      console.error('Failed to flush events:', error);
      throw error;
    }
  }

  /**
   * Get current buffer size
   */
  size(): number {
    return this.events.length;
  }

  /**
   * Check if buffer is empty
   */
  isEmpty(): boolean {
    return this.events.length === 0;
  }

  /**
   * Clear buffer without flushing
   */
  clear(): void {
    this.events = [];
  }

  /**
   * Get all events without removing them
   */
  getEvents(): TestEvent[] {
    return [...this.events];
  }
}
