/**
 * Istanbul HTML report generator.
 * Uses the standard istanbul-reports package to generate a full HTML report
 * with source code display, line-by-line coverage, and drill-down navigation.
 */

import { createContext } from 'istanbul-lib-report';
import { create as createReporter } from 'istanbul-reports';
import { mkdir, rm } from 'fs/promises';
import type { CoverageMerger } from './merger.js';

export interface IstanbulHtmlReportOptions {
  outputDir: string;
}

/**
 * Generate a full Istanbul HTML coverage report in the specified output directory.
 * Returns the path to the generated index.html entry point.
 */
export async function generateIstanbulHtmlReport(
  coverageMerger: CoverageMerger,
  options: IstanbulHtmlReportOptions
): Promise<string> {
  // Clean output directory to remove stale files from previous runs
  await rm(options.outputDir, { recursive: true, force: true }).catch(() => {});
  await mkdir(options.outputDir, { recursive: true });

  // Get the raw coverage map from the merger
  const coverageMap = coverageMerger.getRawCoverageMap();

  // Create Istanbul report context
  const context = createContext({
    dir: options.outputDir,
    watermarks: {
      statements: [50, 80],
      functions: [50, 80],
      branches: [50, 80],
      lines: [50, 80],
    },
    coverageMap,
  });

  // Create HTML reporter
  const reporter = createReporter('html', {
    skipEmpty: false,
    subdir: '',
  });

  // Generate the report
  reporter.execute(context);

  // Return the path to the main index file
  return `${options.outputDir}/index.html`;
}
