/**
 * HTTP client for server authentication
 */

import axios, { type AxiosInstance } from 'axios';
import type { SessionCreationQuotaResponse } from '../types/index.js';
import type { TestEvent } from '../types/index.js';
import { QuotaExhaustedError } from '../reporter/errors.js';

export interface HttpClientOptions {
  token: string;
  serverUrl: string;
}

export interface AuthResponse {
  sessionId: string;
  projectId: string;
  wsUrl?: string;
  kafka?: {
    brokers: string[];
    topic?: string;
    sasl?: {
      mechanism: 'plain' | 'scram-sha-256' | 'scram-sha-512';
      username: string;
      password: string;
    };
    ssl?: boolean;
  };
}

export class HttpClient {
  private client: AxiosInstance;

  constructor(options: HttpClientOptions) {
    this.client = axios.create({
      baseURL: options.serverUrl,
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${options.token}`,
      },
      timeout: 10000,
    });
  }

  /**
   * Authenticate with server and receive Kafka connection config
   */
  async authenticate(): Promise<AuthResponse> {
    try {
      const response = await this.client.post('/auth');
      return response.data;
    } catch (error) {
      // Handle quota exhausted error (402)
      if (axios.isAxiosError(error) && error.response?.status === 402) {
        const quotaError = error.response.data as SessionCreationQuotaResponse;

        // Throw proper Error class instance
        throw new QuotaExhaustedError(quotaError.message, quotaError.details);
      }

      throw new Error(`Authentication failed: ${this.getErrorMessage(error)}`);
    }
  }

  /**
   * Send events via HTTP POST (fallback when Kafka is unavailable)
   */
  async sendEvents(events: TestEvent[]): Promise<void> {
    await this.client.post('/events', { events });
  }

  /**
   * Extract error message from various error types
   */
  private getErrorMessage(error: unknown): string {
    if (axios.isAxiosError(error)) {
      return error.response?.data?.message || error.message;
    }
    if (error instanceof Error) {
      return error.message;
    }
    return String(error);
  }
}
