/**
 * Event delivery manager with Kafka primary, HTTP fallback, and retry logic
 */

import type { TestEvent } from '../types/index.js';
import type { KafkaEventProducer } from './kafka.js';
import type { HttpClient } from './http.js';

export interface DeliveryManagerOptions {
  kafkaProducer: KafkaEventProducer;
  httpClient: HttpClient;
  maxAttempts?: number;
  baseDelayMs?: number;
  debug?: boolean;
  onDebug?: (message: string) => void;
  onError?: (message: string) => void;
  onWarn?: (message: string) => void;
}

type DeliveryChannel = 'kafka' | 'http';

export class EventDeliveryManager {
  private readonly kafkaProducer: KafkaEventProducer;
  private readonly httpClient: HttpClient;
  private readonly maxAttempts: number;
  private readonly baseDelayMs: number;
  private readonly debug: boolean;
  private readonly onDebug: (message: string) => void;
  private readonly onError: (message: string) => void;
  private readonly onWarn: (message: string) => void;

  private kafkaHealthy = true;

  constructor(options: DeliveryManagerOptions) {
    this.kafkaProducer = options.kafkaProducer;
    this.httpClient = options.httpClient;
    this.maxAttempts = options.maxAttempts ?? 3;
    this.baseDelayMs = options.baseDelayMs ?? 500;
    this.debug = options.debug ?? false;
    this.onDebug = options.onDebug ?? (() => {});
    this.onError = options.onError ?? (() => {});
    this.onWarn = options.onWarn ?? (() => {});
  }

  /**
   * Send a batch of events with retry and fallback.
   *
   * Strategy:
   * 1. If Kafka is healthy, try Kafka with reconnect-on-failure
   * 2. If Kafka fails after retries, mark unhealthy and fall back to HTTP
   * 3. If HTTP also fails, throw (buffer will restore events for next flush)
   */
  async sendBatch(events: TestEvent[]): Promise<void> {
    if (events.length === 0) return;

    // Try Kafka first (if still considered healthy)
    if (this.kafkaHealthy) {
      const kafkaSuccess = await this.tryKafkaWithRetry(events);
      if (kafkaSuccess) return;

      // Kafka exhausted — mark unhealthy so future calls skip straight to HTTP
      this.kafkaHealthy = false;
      this.onWarn('Kafka delivery failed — switching to HTTP fallback for remaining events');
    }

    // HTTP fallback
    await this.tryHttpWithRetry(events);
  }

  /**
   * Send a single event (used for run:end which must be sent directly)
   */
  async send(event: TestEvent): Promise<void> {
    await this.sendBatch([event]);
  }

  /**
   * Try sending via Kafka with reconnect attempts.
   * Returns true if delivery succeeded, false if all attempts exhausted.
   */
  private async tryKafkaWithRetry(events: TestEvent[]): Promise<boolean> {
    for (let attempt = 1; attempt <= this.maxAttempts; attempt++) {
      try {
        // If disconnected (after a prior failure), try to reconnect
        if (!this.kafkaProducer.isConnected) {
          if (this.debug) {
            this.onDebug(`Kafka reconnect attempt ${attempt}/${this.maxAttempts}`);
          }
          await this.kafkaProducer.connect();
        }

        await this.kafkaProducer.sendBatch(events);

        if (this.debug) {
          this.onDebug(
            `Kafka delivered ${events.length} events ` +
              `(seq ${events[0].sequence}-${events[events.length - 1].sequence})`
          );
        }
        return true;
      } catch (error) {
        const message = error instanceof Error ? error.message : String(error);

        if (attempt < this.maxAttempts) {
          const delay = this.getBackoffDelay(attempt);
          if (this.debug) {
            this.onDebug(`Kafka attempt ${attempt}/${this.maxAttempts} failed: ${message}. Retrying in ${delay}ms`);
          }
          await this.sleep(delay);
        } else {
          this.onError(`Kafka delivery failed after ${this.maxAttempts} attempts: ${message}`);
        }
      }
    }

    return false;
  }

  /**
   * Try sending via HTTP with retry.
   * Throws if all attempts fail (buffer will restore events).
   */
  private async tryHttpWithRetry(events: TestEvent[]): Promise<void> {
    let lastError: Error | undefined;

    for (let attempt = 1; attempt <= this.maxAttempts; attempt++) {
      try {
        await this.httpClient.sendEvents(events);

        if (this.debug) {
          this.onDebug(
            `HTTP fallback delivered ${events.length} events ` +
              `(seq ${events[0].sequence}-${events[events.length - 1].sequence})`
          );
        }
        return;
      } catch (error) {
        lastError = error instanceof Error ? error : new Error(String(error));
        const message = lastError.message;

        if (attempt < this.maxAttempts) {
          const delay = this.getBackoffDelay(attempt);
          if (this.debug) {
            this.onDebug(`HTTP attempt ${attempt}/${this.maxAttempts} failed: ${message}. Retrying in ${delay}ms`);
          }
          await this.sleep(delay);
        } else {
          this.onError(`HTTP fallback delivery failed after ${this.maxAttempts} attempts: ${message}`);
        }
      }
    }

    throw lastError;
  }

  /** Exponential backoff: baseDelay * 2^(attempt-1) */
  private getBackoffDelay(attempt: number): number {
    return this.baseDelayMs * Math.pow(2, attempt - 1);
  }

  private sleep(ms: number): Promise<void> {
    return new Promise((resolve) => setTimeout(resolve, ms));
  }

  /** Current delivery channel preference */
  get activeChannel(): DeliveryChannel {
    return this.kafkaHealthy ? 'kafka' : 'http';
  }
}
